import { Request, Response, NextFunction } from 'express';
import { UnauthorizedError } from '../../shared/errors/http-errors.js';
import { sendSuccess } from '../../shared/utils/response.js';
import { PresetsService } from './presets.service.js';
import { listPresetsQuerySchema } from './presets.validation.js';
import { CreatePresetInput, UpdatePresetInput } from './presets.types.js';

export class PresetsController {
    constructor(private readonly presetsService: PresetsService) {}

    // POST /presets
    create = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            const preset = await this.presetsService.createPreset(req.body as CreatePresetInput, req.user);
            sendSuccess(res, { preset }, 201);
        } catch (err) { next(err); }
    };

    // GET /presets
    list = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            const parsed = listPresetsQuerySchema.safeParse(req.query);
            const filters = parsed.success ? parsed.data : {};
            const presets = await this.presetsService.listPresets(filters, req.user);
            sendSuccess(res, { presets });
        } catch (err) { next(err); }
    };

    // GET /presets/:presetId
    getDetail = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            const preset = await this.presetsService.getPresetDetail(
                req.params['presetId'] as string,
                req.user
            );
            sendSuccess(res, { preset });
        } catch (err) { next(err); }
    };

    // PATCH /presets/:presetId
    update = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            const preset = await this.presetsService.updatePreset(
                req.params['presetId'] as string,
                req.body as UpdatePresetInput,
                req.user
            );
            sendSuccess(res, { preset });
        } catch (err) { next(err); }
    };

    // DELETE /presets/:presetId
    delete = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            await this.presetsService.deletePreset(
                req.params['presetId'] as string,
                req.user
            );
            sendSuccess(res, null, 200);
        } catch (err) { next(err); }
    };
}

import { Request, Response, NextFunction } from 'express';
import { UnauthorizedError } from '../../shared/errors/http-errors.js';
import { sendSuccess } from '../../shared/utils/response.js';
import { PresetsService } from './presets.service.js';
import { CreatePresetInput, ListPresetsFilters, UpdatePresetInput } from './presets.types.js';

export class PresetsController {
    constructor(private readonly presetsService: PresetsService) {}

    // POST /presets
    create = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            const preset = await this.presetsService.createPreset(req.body as CreatePresetInput, req.user);
            sendSuccess(res, { preset }, 201);
        } catch (err) { next(err); }
    };

    // GET /presets — query params validated by validate(listPresetsQuerySchema, 'query') in routes
    list = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            const filters = req.query as unknown as ListPresetsFilters;
            const { presets, total, limit, offset } = await this.presetsService.listPresets(filters, req.user);
            sendSuccess(res, { presets, pagination: { total, limit, offset } });
        } catch (err) { next(err); }
    };

    // GET /presets/:presetId
    getDetail = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            const preset = await this.presetsService.getPresetDetail(
                req.params['presetId'] as string,
                req.user
            );
            sendSuccess(res, { preset });
        } catch (err) { next(err); }
    };

    // PATCH /presets/:presetId
    update = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            const preset = await this.presetsService.updatePreset(
                req.params['presetId'] as string,
                req.body as UpdatePresetInput,
                req.user
            );
            sendSuccess(res, { preset });
        } catch (err) { next(err); }
    };

    // DELETE /presets/:presetId
    delete = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            await this.presetsService.deletePreset(
                req.params['presetId'] as string,
                req.user
            );
            sendSuccess(res, null, 200);
        } catch (err) { next(err); }
    };
}

import sql from 'mssql';
import { PresetRow } from './presets.types.js';

export interface CreatePresetData {
    id: string;
    organizationId: string | null;
    createdByUserId: string;
    scope: string;
    name: string;
    description?: string;
    configJson: string; // already JSON.stringified
}

export interface UpdatePresetData {
    name?: string;
    description?: string | null;
    configJson?: string; // already JSON.stringified
}

export interface FindPresetsOptions {
    scope?: string;
    organizationId?: string;
    createdByUserId?: string;
    /** For non-super-admin: list only presets the actor can see */
    actorUserId?: string;
    /** When true, returns ALL non-deleted presets (super admin) */
    isSuperAdmin?: boolean;
}

export class PresetsRepository {
    constructor(private readonly pool: sql.ConnectionPool) {}

    // ── Create ────────────────────────────────────────────────────────────────

    async create(data: CreatePresetData): Promise<PresetRow> {
        const result = await this.pool
            .request()
            .input('id',                sql.UniqueIdentifier, data.id)
            .input('organizationId',    sql.UniqueIdentifier, data.organizationId)
            .input('createdByUserId',   sql.UniqueIdentifier, data.createdByUserId)
            .input('scope',             sql.NVarChar(20),     data.scope)
            .input('name',              sql.NVarChar(150),    data.name)
            .input('description',       sql.NVarChar(500),    data.description ?? null)
            .input('configJson',        sql.NVarChar(sql.MAX),data.configJson)
            .query<PresetRow>(`
                INSERT INTO app.training_presets
                    (id, organization_id, created_by_user_id, scope, name, description, config_json)
                OUTPUT
                    INSERTED.id, INSERTED.organization_id, INSERTED.created_by_user_id,
                    INSERTED.scope, INSERTED.name, INSERTED.description, INSERTED.config_json,
                    INSERTED.created_at, INSERTED.updated_at, INSERTED.deleted_at
                VALUES (@id, @organizationId, @createdByUserId, @scope, @name, @description, @configJson)
            `);
        return result.recordset[0];
    }

    // ── Find by ID ────────────────────────────────────────────────────────────

    async findById(presetId: string): Promise<PresetRow | null> {
        const result = await this.pool
            .request()
            .input('id', sql.UniqueIdentifier, presetId)
            .query<PresetRow>(`
                SELECT id, organization_id, created_by_user_id, scope, name, description,
                       config_json, created_at, updated_at, deleted_at
                FROM app.training_presets
                WHERE id = @id AND deleted_at IS NULL
            `);
        return result.recordset[0] ?? null;
    }

    // ── List ──────────────────────────────────────────────────────────────────

    /**
     * List presets visible to the actor:
     *   — personal presets they created
     *   — org presets from orgs they are an ACTIVE member of
     * Super admin: all non-deleted presets (with optional filters).
     */
    async findMany(opts: FindPresetsOptions): Promise<PresetRow[]> {
        const req = this.pool.request();

        let baseWhere = `tp.deleted_at IS NULL`;

        if (opts.scope) {
            req.input('scope', sql.NVarChar(20), opts.scope);
            baseWhere += ` AND tp.scope = @scope`;
        }

        if (opts.organizationId) {
            req.input('organizationId', sql.UniqueIdentifier, opts.organizationId);
            baseWhere += ` AND tp.organization_id = @organizationId`;
        }

        if (opts.createdByUserId) {
            req.input('createdByUserId', sql.UniqueIdentifier, opts.createdByUserId);
            baseWhere += ` AND tp.created_by_user_id = @createdByUserId`;
        }

        let query: string;

        if (opts.isSuperAdmin) {
            query = `
                SELECT tp.id, tp.organization_id, tp.created_by_user_id, tp.scope,
                       tp.name, tp.description, tp.config_json, tp.created_at, tp.updated_at, tp.deleted_at
                FROM app.training_presets tp
                WHERE ${baseWhere}
                ORDER BY tp.created_at DESC
            `;
        } else {
            // Actor sees: own personal presets OR org presets from their active orgs
            req.input('actorUserId', sql.UniqueIdentifier, opts.actorUserId!);
            query = `
                SELECT tp.id, tp.organization_id, tp.created_by_user_id, tp.scope,
                       tp.name, tp.description, tp.config_json, tp.created_at, tp.updated_at, tp.deleted_at
                FROM app.training_presets tp
                WHERE ${baseWhere}
                  AND (
                      -- Personal preset owned by actor
                      (tp.scope = N'USER' AND tp.created_by_user_id = @actorUserId)
                      OR
                      -- Org preset from an org the actor is an active member of
                      (tp.scope = N'ORGANIZATION' AND EXISTS (
                          SELECT 1 FROM app.organization_memberships om
                          WHERE om.organization_id = tp.organization_id
                            AND om.user_id = @actorUserId
                            AND om.status = N'ACTIVE'
                            AND om.left_at IS NULL
                      ))
                  )
                ORDER BY tp.created_at DESC
            `;
        }

        const result = await req.query<PresetRow>(query);
        return result.recordset;
    }

    // ── Update ────────────────────────────────────────────────────────────────

    async update(presetId: string, data: UpdatePresetData): Promise<PresetRow | null> {
        const req = this.pool.request().input('id', sql.UniqueIdentifier, presetId);

        const setClauses: string[] = [`updated_at = SYSUTCDATETIME()`];

        if (data.name !== undefined) {
            req.input('name', sql.NVarChar(150), data.name);
            setClauses.push(`name = @name`);
        }
        if (data.description !== undefined) {
            req.input('description', sql.NVarChar(500), data.description);
            setClauses.push(`description = @description`);
        }
        if (data.configJson !== undefined) {
            req.input('configJson', sql.NVarChar(sql.MAX), data.configJson);
            setClauses.push(`config_json = @configJson`);
        }

        const result = await req.query<PresetRow>(`
            UPDATE app.training_presets
            SET ${setClauses.join(', ')}
            OUTPUT
                INSERTED.id, INSERTED.organization_id, INSERTED.created_by_user_id,
                INSERTED.scope, INSERTED.name, INSERTED.description, INSERTED.config_json,
                INSERTED.created_at, INSERTED.updated_at, INSERTED.deleted_at
            WHERE id = @id AND deleted_at IS NULL
        `);
        return result.recordset[0] ?? null;
    }

    // ── Soft Delete ───────────────────────────────────────────────────────────

    async softDelete(presetId: string): Promise<void> {
        await this.pool
            .request()
            .input('id', sql.UniqueIdentifier, presetId)
            .query(`
                UPDATE app.training_presets
                SET deleted_at = SYSUTCDATETIME()
                WHERE id = @id AND deleted_at IS NULL
            `);
    }
}

import sql from 'mssql';
import { PresetRow } from './presets.types.js';

export interface CreatePresetData {
    id: string;
    organizationId: string | null;
    createdByUserId: string;
    scope: string;
    name: string;
    description?: string;
    configJson: string; // already JSON.stringified
}

export interface UpdatePresetData {
    name?: string;
    description?: string | null;
    configJson?: string; // already JSON.stringified
}

export interface FindPresetsOptions {
    scope?: string;
    organizationId?: string;
    createdByUserId?: string;
    /** For non-super-admin: list only presets the actor can see */
    actorUserId?: string;
    /** When true, returns ALL non-deleted presets (super admin) */
    isSuperAdmin?: boolean;
    limit:  number;
    offset: number;
}

export class PresetsRepository {
    constructor(private readonly pool: sql.ConnectionPool) {}

    // ── Create ────────────────────────────────────────────────────────────────

    async create(data: CreatePresetData): Promise<PresetRow> {
        const result = await this.pool
            .request()
            .input('id',                sql.UniqueIdentifier, data.id)
            .input('organizationId',    sql.UniqueIdentifier, data.organizationId)
            .input('createdByUserId',   sql.UniqueIdentifier, data.createdByUserId)
            .input('scope',             sql.NVarChar(20),     data.scope)
            .input('name',              sql.NVarChar(150),    data.name)
            .input('description',       sql.NVarChar(500),    data.description ?? null)
            .input('configJson',        sql.NVarChar(sql.MAX),data.configJson)
            .query<PresetRow>(`
                INSERT INTO app.training_presets
                    (id, organization_id, created_by_user_id, scope, name, description, config_json)
                OUTPUT
                    INSERTED.id, INSERTED.organization_id, INSERTED.created_by_user_id,
                    INSERTED.scope, INSERTED.name, INSERTED.description, INSERTED.config_json,
                    INSERTED.created_at, INSERTED.updated_at, INSERTED.deleted_at
                VALUES (@id, @organizationId, @createdByUserId, @scope, @name, @description, @configJson)
            `);
        return result.recordset[0];
    }

    // ── Find by ID ────────────────────────────────────────────────────────────

    async findById(presetId: string): Promise<PresetRow | null> {
        const result = await this.pool
            .request()
            .input('id', sql.UniqueIdentifier, presetId)
            .query<PresetRow>(`
                SELECT id, organization_id, created_by_user_id, scope, name, description,
                       config_json, created_at, updated_at, deleted_at
                FROM app.training_presets
                WHERE id = @id AND deleted_at IS NULL
            `);
        return result.recordset[0] ?? null;
    }

    // ── List ──────────────────────────────────────────────────────────────────

    /**
     * List presets visible to the actor:
     *   — personal presets they created
     *   — org presets from orgs they are an ACTIVE member of
     * Super admin: all non-deleted presets (with optional filters).
     */
    async findMany(opts: FindPresetsOptions): Promise<PresetRow[]> {
        const req = this.pool.request();
        req.input('limit',  sql.Int, opts.limit);
        req.input('offset', sql.Int, opts.offset);

        let baseWhere = `tp.deleted_at IS NULL`;

        if (opts.scope) {
            req.input('scope', sql.NVarChar(20), opts.scope);
            baseWhere += ` AND tp.scope = @scope`;
        }

        if (opts.organizationId) {
            req.input('organizationId', sql.UniqueIdentifier, opts.organizationId);
            baseWhere += ` AND tp.organization_id = @organizationId`;
        }

        if (opts.createdByUserId) {
            req.input('createdByUserId', sql.UniqueIdentifier, opts.createdByUserId);
            baseWhere += ` AND tp.created_by_user_id = @createdByUserId`;
        }

        const pagination = `ORDER BY tp.created_at DESC
            OFFSET @offset ROWS FETCH NEXT @limit ROWS ONLY`;

        let query: string;

        if (opts.isSuperAdmin) {
            query = `
                SELECT tp.id, tp.organization_id, tp.created_by_user_id, tp.scope,
                       tp.name, tp.description, tp.config_json, tp.created_at, tp.updated_at, tp.deleted_at
                FROM app.training_presets tp
                WHERE ${baseWhere}
                ${pagination}
            `;
        } else {
            // Actor sees: own personal presets OR org presets from their active orgs
            req.input('actorUserId', sql.UniqueIdentifier, opts.actorUserId!);
            query = `
                SELECT tp.id, tp.organization_id, tp.created_by_user_id, tp.scope,
                       tp.name, tp.description, tp.config_json, tp.created_at, tp.updated_at, tp.deleted_at
                FROM app.training_presets tp
                WHERE ${baseWhere}
                  AND (
                      -- Personal preset owned by actor
                      (tp.scope = N'USER' AND tp.created_by_user_id = @actorUserId)
                      OR
                      -- Org preset from an org the actor is an active member of
                      (tp.scope = N'ORGANIZATION' AND EXISTS (
                          SELECT 1 FROM app.organization_memberships om
                          WHERE om.organization_id = tp.organization_id
                            AND om.user_id = @actorUserId
                            AND om.status = N'ACTIVE'
                            AND om.left_at IS NULL
                      ))
                  )
                ${pagination}
            `;
        }

        const result = await req.query<PresetRow>(query);
        return result.recordset;
    }

    /**
     * Returns the total count of presets matching the same filters and visibility,
     * without pagination. Run in parallel with findMany().
     */
    async countMany(opts: Omit<FindPresetsOptions, 'limit' | 'offset'>): Promise<number> {
        const req = this.pool.request();

        let baseWhere = `tp.deleted_at IS NULL`;

        if (opts.scope) {
            req.input('scope', sql.NVarChar(20), opts.scope);
            baseWhere += ` AND tp.scope = @scope`;
        }

        if (opts.organizationId) {
            req.input('organizationId', sql.UniqueIdentifier, opts.organizationId);
            baseWhere += ` AND tp.organization_id = @organizationId`;
        }

        if (opts.createdByUserId) {
            req.input('createdByUserId', sql.UniqueIdentifier, opts.createdByUserId);
            baseWhere += ` AND tp.created_by_user_id = @createdByUserId`;
        }

        let query: string;

        if (opts.isSuperAdmin) {
            query = `
                SELECT COUNT(1) AS total
                FROM app.training_presets tp
                WHERE ${baseWhere}
            `;
        } else {
            req.input('actorUserId', sql.UniqueIdentifier, opts.actorUserId!);
            query = `
                SELECT COUNT(1) AS total
                FROM app.training_presets tp
                WHERE ${baseWhere}
                  AND (
                      (tp.scope = N'USER' AND tp.created_by_user_id = @actorUserId)
                      OR
                      (tp.scope = N'ORGANIZATION' AND EXISTS (
                          SELECT 1 FROM app.organization_memberships om
                          WHERE om.organization_id = tp.organization_id
                            AND om.user_id = @actorUserId
                            AND om.status = N'ACTIVE'
                            AND om.left_at IS NULL
                      ))
                  )
            `;
        }

        const result = await req.query<{ total: number }>(query);
        return result.recordset[0]?.total ?? 0;
    }

    // ── Update ────────────────────────────────────────────────────────────────

    async update(presetId: string, data: UpdatePresetData): Promise<PresetRow | null> {
        const req = this.pool.request().input('id', sql.UniqueIdentifier, presetId);

        const setClauses: string[] = [`updated_at = SYSUTCDATETIME()`];

        if (data.name !== undefined) {
            req.input('name', sql.NVarChar(150), data.name);
            setClauses.push(`name = @name`);
        }
        if (data.description !== undefined) {
            req.input('description', sql.NVarChar(500), data.description);
            setClauses.push(`description = @description`);
        }
        if (data.configJson !== undefined) {
            req.input('configJson', sql.NVarChar(sql.MAX), data.configJson);
            setClauses.push(`config_json = @configJson`);
        }

        const result = await req.query<PresetRow>(`
            UPDATE app.training_presets
            SET ${setClauses.join(', ')}
            OUTPUT
                INSERTED.id, INSERTED.organization_id, INSERTED.created_by_user_id,
                INSERTED.scope, INSERTED.name, INSERTED.description, INSERTED.config_json,
                INSERTED.created_at, INSERTED.updated_at, INSERTED.deleted_at
            WHERE id = @id AND deleted_at IS NULL
        `);
        return result.recordset[0] ?? null;
    }

    // ── Soft Delete ───────────────────────────────────────────────────────────

    async softDelete(presetId: string): Promise<void> {
        await this.pool
            .request()
            .input('id', sql.UniqueIdentifier, presetId)
            .query(`
                UPDATE app.training_presets
                SET deleted_at = SYSUTCDATETIME()
                WHERE id = @id AND deleted_at IS NULL
            `);
    }
}

import { Router } from 'express';
import { getDb } from '../../config/database.js';
import { authMiddleware } from '../../middlewares/auth.middleware.js';
import { validate } from '../../shared/middlewares/validate.middleware.js';
import { OrganizationsRepository } from '../organizations/organizations.repository.js';
import { PresetsRepository } from './presets.repository.js';
import { PresetsService } from './presets.service.js';
import { PresetsController } from './presets.controller.js';
import {
    createPresetSchema,
    updatePresetSchema,
    presetIdParamSchema,
} from './presets.validation.js';

export async function createPresetsRouter(): Promise<Router> {
    const pool = await getDb();

    const orgsRepo    = new OrganizationsRepository(pool);
    const presetsRepo = new PresetsRepository(pool);
    const service     = new PresetsService(presetsRepo, orgsRepo);
    const controller  = new PresetsController(service);

    const router = Router();

    // All routes require a valid access token
    router.use(authMiddleware);

    // POST /presets
    router.post('/', validate(createPresetSchema), controller.create);

    // GET /presets
    router.get('/', controller.list);

    // GET /presets/:presetId
    router.get('/:presetId', validate(presetIdParamSchema, 'params'), controller.getDetail);

    // PATCH /presets/:presetId
    router.patch(
        '/:presetId',
        validate(presetIdParamSchema, 'params'),
        validate(updatePresetSchema),
        controller.update
    );

    // DELETE /presets/:presetId
    router.delete('/:presetId', validate(presetIdParamSchema, 'params'), controller.delete);

    return router;
}

import { Router } from 'express';
import { getDb } from '../../config/database.js';
import { authMiddleware } from '../../middlewares/auth.middleware.js';
import { validate } from '../../shared/middlewares/validate.middleware.js';
import { OrganizationsRepository } from '../organizations/organizations.repository.js';
import { PresetsRepository } from './presets.repository.js';
import { PresetsService } from './presets.service.js';
import { PresetsController } from './presets.controller.js';
import {
    createPresetSchema,
    updatePresetSchema,
    presetIdParamSchema,
    listPresetsQuerySchema,
} from './presets.validation.js';

export async function createPresetsRouter(): Promise<Router> {
    const pool = await getDb();

    const orgsRepo    = new OrganizationsRepository(pool);
    const presetsRepo = new PresetsRepository(pool);
    const service     = new PresetsService(presetsRepo, orgsRepo);
    const controller  = new PresetsController(service);

    const router = Router();

    // All routes require a valid access token
    router.use(authMiddleware);

    // POST /presets
    router.post('/', validate(createPresetSchema), controller.create);

    // GET /presets
    router.get('/', validate(listPresetsQuerySchema, 'query'), controller.list);

    // GET /presets/:presetId
    router.get('/:presetId', validate(presetIdParamSchema, 'params'), controller.getDetail);

    // PATCH /presets/:presetId
    router.patch(
        '/:presetId',
        validate(presetIdParamSchema, 'params'),
        validate(updatePresetSchema),
        controller.update
    );

    // DELETE /presets/:presetId
    router.delete('/:presetId', validate(presetIdParamSchema, 'params'), controller.delete);

    return router;
}

import { randomUUID } from 'crypto';
import {
    ForbiddenError,
    NotFoundError,
} from '../../shared/errors/http-errors.js';
import { AuthUser } from '../../shared/types/auth-user.types.js';
import { OrganizationsRepository } from '../organizations/organizations.repository.js';
import { PresetsRepository } from './presets.repository.js';
import { mapPresetSummary, mapPresetDetail } from './presets.mapper.js';
import {
    CreatePresetInput,
    UpdatePresetInput,
    ListPresetsFilters,
    PresetSummary,
    PresetDetail,
    PresetRow,
} from './presets.types.js';

export class PresetsService {
    constructor(
        private readonly presetsRepo: PresetsRepository,
        private readonly orgsRepo:    OrganizationsRepository
    ) {}

    // ── Create Preset ─────────────────────────────────────────────────────────

    async createPreset(input: CreatePresetInput, actor: AuthUser): Promise<PresetDetail> {
        if (input.scope === 'ORGANIZATION') {
            if (!input.organizationId) {
                throw new ForbiddenError('organizationId is required for ORGANIZATION scoped presets.');
            }
            await this.requireOrgPermission(input.organizationId, actor, 'presets.manage');
        }

        const row = await this.presetsRepo.create({
            id:              randomUUID(),
            organizationId:  input.scope === 'ORGANIZATION' ? (input.organizationId ?? null) : null,
            createdByUserId: actor.userId,
            scope:           input.scope,
            name:            input.name,
            description:     input.description,
            configJson:      JSON.stringify(input.configJson),
        });

        return mapPresetDetail(row);
    }

    // ── List Presets ──────────────────────────────────────────────────────────

    async listPresets(filters: ListPresetsFilters, actor: AuthUser): Promise<PresetSummary[]> {
        // If filtering by org, require active membership first
        if (filters.organizationId && !actor.isSuperAdmin) {
            await this.requireActiveMember(filters.organizationId, actor);
        }

        const rows = await this.presetsRepo.findMany({
            scope:           filters.scope,
            organizationId:  filters.organizationId,
            createdByUserId: filters.createdByUserId,
            actorUserId:     actor.userId,
            isSuperAdmin:    actor.isSuperAdmin,
        });

        return rows.map(mapPresetSummary);
    }

    // ── Get Preset Detail ─────────────────────────────────────────────────────

    async getPresetDetail(presetId: string, actor: AuthUser): Promise<PresetDetail> {
        const row = await this.requirePresetExists(presetId);
        await this.assertCanRead(row, actor);
        return mapPresetDetail(row);
    }

    // ── Update Preset ─────────────────────────────────────────────────────────

    async updatePreset(presetId: string, input: UpdatePresetInput, actor: AuthUser): Promise<PresetDetail> {
        const row = await this.requirePresetExists(presetId);
        await this.assertCanWrite(row, actor);

        const updated = await this.presetsRepo.update(presetId, {
            name:        input.name,
            description: input.description,
            configJson:  input.configJson !== undefined ? JSON.stringify(input.configJson) : undefined,
        });

        if (!updated) throw new NotFoundError('Preset not found after update.');
        return mapPresetDetail(updated);
    }

    // ── Delete Preset ─────────────────────────────────────────────────────────

    /**
     * Soft-delete. Idempotent — deleting an already-deleted preset silently succeeds.
     */
    async deletePreset(presetId: string, actor: AuthUser): Promise<void> {
        const row = await this.presetsRepo.findById(presetId);
        if (!row) return; // already deleted or never existed — idempotent

        await this.assertCanWrite(row, actor);
        await this.presetsRepo.softDelete(presetId);
    }

    // ── Private Helpers ───────────────────────────────────────────────────────

    private async requirePresetExists(presetId: string): Promise<PresetRow> {
        const row = await this.presetsRepo.findById(presetId);
        if (!row) throw new NotFoundError('Preset not found.');
        return row;
    }

    /**
     * Read access:
     *   - Super admin: always
     *   - USER preset: only the owner
     *   - ORGANIZATION preset: any active member of the org
     */
    private async assertCanRead(row: PresetRow, actor: AuthUser): Promise<void> {
        if (actor.isSuperAdmin) return;

        if (row.scope === 'USER') {
            if (row.created_by_user_id !== actor.userId) {
                throw new ForbiddenError('You do not have access to this preset.');
            }
            return;
        }

        // ORGANIZATION scope
        await this.requireActiveMember(row.organization_id!, actor);
    }

    /**
     * Write access (update / delete):
     *   - Super admin: always
     *   - USER preset: only the owner
     *   - ORGANIZATION preset: requires presets.manage
     */
    private async assertCanWrite(row: PresetRow, actor: AuthUser): Promise<void> {
        if (actor.isSuperAdmin) return;

        if (row.scope === 'USER') {
            if (row.created_by_user_id !== actor.userId) {
                throw new ForbiddenError('You do not have permission to modify this preset.');
            }
            return;
        }

        // ORGANIZATION scope
        await this.requireOrgPermission(row.organization_id!, actor, 'presets.manage');
    }

    private async requireActiveMember(organizationId: string, actor: AuthUser): Promise<void> {
        if (actor.isSuperAdmin) return;
        const membership = await this.orgsRepo.findMembership(organizationId, actor.userId);
        if (!membership || membership.status !== 'ACTIVE' || membership.left_at !== null) {
            throw new ForbiddenError('You are not an active member of this organization.');
        }
    }

    private async requireOrgPermission(
        organizationId: string,
        actor: AuthUser,
        code: string
    ): Promise<void> {
        if (actor.isSuperAdmin) return;

        const membership = await this.orgsRepo.findMembership(organizationId, actor.userId);
        if (!membership || membership.status !== 'ACTIVE' || membership.left_at !== null) {
            throw new ForbiddenError('You are not an active member of this organization.');
        }

        const permissions = await this.orgsRepo.findEffectivePermissions(organizationId, actor.userId);
        if (!permissions.includes(code)) {
            throw new ForbiddenError(`You do not have the required permission: ${code}`);
        }
    }
}

import { randomUUID } from 'crypto';
import {
    ForbiddenError,
    NotFoundError,
} from '../../shared/errors/http-errors.js';
import { AuthUser } from '../../shared/types/auth-user.types.js';
import { OrganizationsRepository } from '../organizations/organizations.repository.js';
import { PresetsRepository } from './presets.repository.js';
import { mapPresetSummary, mapPresetDetail } from './presets.mapper.js';
import {
    CreatePresetInput,
    UpdatePresetInput,
    ListPresetsFilters,
    PresetSummary,
    PresetDetail,
    PresetRow,
    PresetListResult,
} from './presets.types.js';

export class PresetsService {
    constructor(
        private readonly presetsRepo: PresetsRepository,
        private readonly orgsRepo:    OrganizationsRepository
    ) {}

    // ── Create Preset ─────────────────────────────────────────────────────────

    async createPreset(input: CreatePresetInput, actor: AuthUser): Promise<PresetDetail> {
        if (input.scope === 'ORGANIZATION') {
            if (!input.organizationId) {
                throw new ForbiddenError('organizationId is required for ORGANIZATION scoped presets.');
            }
            await this.requireOrgPermission(input.organizationId, actor, 'presets.manage');
        }

        const row = await this.presetsRepo.create({
            id:              randomUUID(),
            organizationId:  input.scope === 'ORGANIZATION' ? (input.organizationId ?? null) : null,
            createdByUserId: actor.userId,
            scope:           input.scope,
            name:            input.name,
            description:     input.description,
            configJson:      JSON.stringify(input.configJson),
        });

        return mapPresetDetail(row);
    }

    // ── List Presets ──────────────────────────────────────────────────────────

    async listPresets(filters: ListPresetsFilters, actor: AuthUser): Promise<PresetListResult> {
        // If filtering by org, require active membership first
        if (filters.organizationId && !actor.isSuperAdmin) {
            await this.requireActiveMember(filters.organizationId, actor);
        }

        const limit  = filters.limit  ?? 50;
        const offset = filters.offset ?? 0;

        const queryOpts = {
            scope:           filters.scope,
            organizationId:  filters.organizationId,
            createdByUserId: filters.createdByUserId,
            actorUserId:     actor.userId,
            isSuperAdmin:    actor.isSuperAdmin,
        };

        const [rows, total] = await Promise.all([
            this.presetsRepo.findMany({ ...queryOpts, limit, offset }),
            this.presetsRepo.countMany(queryOpts),
        ]);

        return { presets: rows.map(mapPresetSummary), total, limit, offset };
    }

    // ── Get Preset Detail ─────────────────────────────────────────────────────

    async getPresetDetail(presetId: string, actor: AuthUser): Promise<PresetDetail> {
        const row = await this.requirePresetExists(presetId);
        await this.assertCanRead(row, actor);
        return mapPresetDetail(row);
    }

    // ── Update Preset ─────────────────────────────────────────────────────────

    async updatePreset(presetId: string, input: UpdatePresetInput, actor: AuthUser): Promise<PresetDetail> {
        const row = await this.requirePresetExists(presetId);
        await this.assertCanWrite(row, actor);

        const updated = await this.presetsRepo.update(presetId, {
            name:        input.name,
            description: input.description,
            configJson:  input.configJson !== undefined ? JSON.stringify(input.configJson) : undefined,
        });

        if (!updated) throw new NotFoundError('Preset not found after update.');
        return mapPresetDetail(updated);
    }

    // ── Delete Preset ─────────────────────────────────────────────────────────

    /**
     * Soft-delete. Idempotent — deleting an already-deleted preset silently succeeds.
     */
    async deletePreset(presetId: string, actor: AuthUser): Promise<void> {
        const row = await this.presetsRepo.findById(presetId);
        if (!row) return; // already deleted or never existed — idempotent

        await this.assertCanWrite(row, actor);
        await this.presetsRepo.softDelete(presetId);
    }

    // ── Private Helpers ───────────────────────────────────────────────────────

    private async requirePresetExists(presetId: string): Promise<PresetRow> {
        const row = await this.presetsRepo.findById(presetId);
        if (!row) throw new NotFoundError('Preset not found.');
        return row;
    }

    /**
     * Read access:
     *   - Super admin: always
     *   - USER preset: only the owner
     *   - ORGANIZATION preset: any active member of the org
     */
    private async assertCanRead(row: PresetRow, actor: AuthUser): Promise<void> {
        if (actor.isSuperAdmin) return;

        if (row.scope === 'USER') {
            if (row.created_by_user_id !== actor.userId) {
                throw new ForbiddenError('You do not have access to this preset.');
            }
            return;
        }

        // ORGANIZATION scope
        await this.requireActiveMember(row.organization_id!, actor);
    }

    /**
     * Write access (update / delete):
     *   - Super admin: always
     *   - USER preset: only the owner
     *   - ORGANIZATION preset: requires presets.manage
     */
    private async assertCanWrite(row: PresetRow, actor: AuthUser): Promise<void> {
        if (actor.isSuperAdmin) return;

        if (row.scope === 'USER') {
            if (row.created_by_user_id !== actor.userId) {
                throw new ForbiddenError('You do not have permission to modify this preset.');
            }
            return;
        }

        // ORGANIZATION scope
        await this.requireOrgPermission(row.organization_id!, actor, 'presets.manage');
    }

    private async requireActiveMember(organizationId: string, actor: AuthUser): Promise<void> {
        if (actor.isSuperAdmin) return;
        const membership = await this.orgsRepo.findMembership(organizationId, actor.userId);
        if (!membership || membership.status !== 'ACTIVE' || membership.left_at !== null) {
            throw new ForbiddenError('You are not an active member of this organization.');
        }
    }

    private async requireOrgPermission(
        organizationId: string,
        actor: AuthUser,
        code: string
    ): Promise<void> {
        if (actor.isSuperAdmin) return;

        const membership = await this.orgsRepo.findMembership(organizationId, actor.userId);
        if (!membership || membership.status !== 'ACTIVE' || membership.left_at !== null) {
            throw new ForbiddenError('You are not an active member of this organization.');
        }

        const permissions = await this.orgsRepo.findEffectivePermissions(organizationId, actor.userId);
        if (!permissions.includes(code)) {
            throw new ForbiddenError(`You do not have the required permission: ${code}`);
        }
    }
}

