import sql from 'mssql';
import {
    TrainingSessionRow,
    TrainingSessionActivePodRow,
    TrainingSessionEventRow,
    ListSessionsFilters,
} from './sessions.types.js';

export interface CreateSessionData {
    id: string;
    organizationId: string;
    deviceKitId: string;
    hubDeviceId?: string;

    startedByUserId?: string;
    assignedToUserId?: string;
    teamId?: string;

    origin: string;
    clientSessionId: string;
    status: string;
    endMode: string;
    presetId?: string;
    trainingMode: string;
    configJson: string; // pre-serialised JSON string

    sessionStartedAt: Date;
    sessionEndedAt: Date;
    durationMs: number;

    score?: number;
    hitCount: number;
    missCount: number;
    accuracyPercent?: number;

    avgReactionMs?: number;
    bestReactionMs?: number;
    worstReactionMs?: number;

    activePodCount: number;
    totalEventsCount: number;
    notes?: string;
}

export interface CreateActivePodData {
    trainingSessionId: string;
    podDeviceId: string;
    podOrder?: number;
}

export interface CreateEventData {
    trainingSessionId: string;
    podDeviceId?: string;
    eventIndex: number;
    eventType: string;
    eventTimestamp: Date;
    elapsedMs?: number;
    reactionTimeMs?: number;
    isCorrect?: boolean;
    payloadJson?: string; // pre-serialised JSON string
}

export interface UpdateAssignmentData {
    assignedToUserId?: string | null;
    teamId?: string | null;
    assignedByUserId: string;
}

export class SessionsRepository {
    constructor(private readonly pool: sql.ConnectionPool) {}

    // ── Idempotency Check ─────────────────────────────────────────────────────

    /**
     * Returns an existing session if it was already synced with the same
     * (organization_id, client_session_id) pair. Includes deleted sessions
     * so re-sync of a deleted session is properly detected.
     */
    async findByClientSessionId(
        organizationId: string,
        clientSessionId: string
    ): Promise<TrainingSessionRow | null> {
        const result = await this.pool
            .request()
            .input('organizationId',  sql.UniqueIdentifier, organizationId)
            .input('clientSessionId', sql.NVarChar(100),     clientSessionId)
            .query<TrainingSessionRow>(`
                SELECT
                    id, organization_id, device_kit_id, hub_device_id,
                    started_by_user_id, assigned_to_user_id, assigned_by_user_id, team_id,
                    origin, sync_status, client_session_id,
                    status, end_mode, preset_id, training_mode, config_json,
                    session_started_at, session_ended_at, duration_ms,
                    score, hit_count, miss_count, accuracy_percent,
                    avg_reaction_ms, best_reaction_ms, worst_reaction_ms,
                    active_pod_count, total_events_count, notes,
                    created_at, updated_at, deleted_at
                FROM app.training_sessions
                WHERE organization_id   = @organizationId
                  AND client_session_id = @clientSessionId
            `);
        return result.recordset[0] ?? null;
    }

    // ── Sync (transactional) ──────────────────────────────────────────────────

    /**
     * Inserts session + active pods + events in a single transaction.
     * Caller must ensure idempotency check has already run.
     */
    async syncSession(
        sessionData: CreateSessionData,
        pods: CreateActivePodData[],
        events: CreateEventData[]
    ): Promise<TrainingSessionRow> {
        const transaction = new sql.Transaction(this.pool);
        await transaction.begin();

        try {
            // 1. Insert session row
            const sessionResult = await transaction
                .request()
                .input('id',               sql.UniqueIdentifier, sessionData.id)
                .input('organizationId',   sql.UniqueIdentifier, sessionData.organizationId)
                .input('deviceKitId',      sql.UniqueIdentifier, sessionData.deviceKitId)
                .input('hubDeviceId',      sql.UniqueIdentifier, sessionData.hubDeviceId ?? null)
                .input('startedByUserId',  sql.UniqueIdentifier, sessionData.startedByUserId ?? null)
                .input('assignedToUserId', sql.UniqueIdentifier, sessionData.assignedToUserId ?? null)
                .input('teamId',           sql.UniqueIdentifier, sessionData.teamId ?? null)
                .input('origin',           sql.NVarChar(20),     sessionData.origin)
                .input('clientSessionId',  sql.NVarChar(100),    sessionData.clientSessionId)
                .input('status',           sql.NVarChar(20),     sessionData.status)
                .input('endMode',          sql.NVarChar(20),     sessionData.endMode)
                .input('presetId',         sql.UniqueIdentifier, sessionData.presetId ?? null)
                .input('trainingMode',     sql.NVarChar(50),     sessionData.trainingMode)
                .input('configJson',       sql.NVarChar(sql.MAX), sessionData.configJson)
                .input('sessionStartedAt', sql.DateTime2,        sessionData.sessionStartedAt)
                .input('sessionEndedAt',   sql.DateTime2,        sessionData.sessionEndedAt)
                .input('durationMs',       sql.BigInt,           sessionData.durationMs)
                .input('score',            sql.Int,              sessionData.score ?? null)
                .input('hitCount',         sql.Int,              sessionData.hitCount)
                .input('missCount',        sql.Int,              sessionData.missCount)
                .input('accuracyPercent',  sql.Decimal(5, 2),    sessionData.accuracyPercent ?? null)
                .input('avgReactionMs',    sql.Decimal(10, 2),   sessionData.avgReactionMs ?? null)
                .input('bestReactionMs',   sql.Decimal(10, 2),   sessionData.bestReactionMs ?? null)
                .input('worstReactionMs',  sql.Decimal(10, 2),   sessionData.worstReactionMs ?? null)
                .input('activePodCount',   sql.Int,              sessionData.activePodCount)
                .input('totalEventsCount', sql.Int,              sessionData.totalEventsCount)
                .input('notes',            sql.NVarChar(1000),   sessionData.notes ?? null)
                .query<TrainingSessionRow>(`
                    INSERT INTO app.training_sessions (
                        id, organization_id, device_kit_id, hub_device_id,
                        started_by_user_id, assigned_to_user_id, team_id,
                        origin, sync_status, client_session_id,
                        status, end_mode, preset_id, training_mode, config_json,
                        session_started_at, session_ended_at, duration_ms,
                        score, hit_count, miss_count, accuracy_percent,
                        avg_reaction_ms, best_reaction_ms, worst_reaction_ms,
                        active_pod_count, total_events_count, notes
                    )
                    OUTPUT
                        INSERTED.id, INSERTED.organization_id, INSERTED.device_kit_id, INSERTED.hub_device_id,
                        INSERTED.started_by_user_id, INSERTED.assigned_to_user_id, INSERTED.assigned_by_user_id, INSERTED.team_id,
                        INSERTED.origin, INSERTED.sync_status, INSERTED.client_session_id,
                        INSERTED.status, INSERTED.end_mode, INSERTED.preset_id, INSERTED.training_mode, INSERTED.config_json,
                        INSERTED.session_started_at, INSERTED.session_ended_at, INSERTED.duration_ms,
                        INSERTED.score, INSERTED.hit_count, INSERTED.miss_count, INSERTED.accuracy_percent,
                        INSERTED.avg_reaction_ms, INSERTED.best_reaction_ms, INSERTED.worst_reaction_ms,
                        INSERTED.active_pod_count, INSERTED.total_events_count, INSERTED.notes,
                        INSERTED.created_at, INSERTED.updated_at, INSERTED.deleted_at
                    VALUES (
                        @id, @organizationId, @deviceKitId, @hubDeviceId,
                        @startedByUserId, @assignedToUserId, @teamId,
                        @origin, N'SYNCED', @clientSessionId,
                        @status, @endMode, @presetId, @trainingMode, @configJson,
                        @sessionStartedAt, @sessionEndedAt, @durationMs,
                        @score, @hitCount, @missCount, @accuracyPercent,
                        @avgReactionMs, @bestReactionMs, @worstReactionMs,
                        @activePodCount, @totalEventsCount, @notes
                    )
                `);

            const session = sessionResult.recordset[0];

            // 2. Insert active pods
            for (const pod of pods) {
                await transaction
                    .request()
                    .input('trainingSessionId', sql.UniqueIdentifier, pod.trainingSessionId)
                    .input('podDeviceId',       sql.UniqueIdentifier, pod.podDeviceId)
                    .input('podOrder',          sql.Int,              pod.podOrder ?? null)
                    .query(`
                        INSERT INTO app.training_session_active_pods
                            (training_session_id, pod_device_id, pod_order)
                        VALUES (@trainingSessionId, @podDeviceId, @podOrder)
                    `);
            }

            // 3. Insert events
            for (const evt of events) {
                await transaction
                    .request()
                    .input('trainingSessionId', sql.UniqueIdentifier, evt.trainingSessionId)
                    .input('podDeviceId',       sql.UniqueIdentifier, evt.podDeviceId ?? null)
                    .input('eventIndex',        sql.Int,              evt.eventIndex)
                    .input('eventType',         sql.NVarChar(50),     evt.eventType)
                    .input('eventTimestamp',    sql.DateTime2,        evt.eventTimestamp)
                    .input('elapsedMs',         sql.BigInt,           evt.elapsedMs ?? null)
                    .input('reactionTimeMs',    sql.Decimal(10, 2),   evt.reactionTimeMs ?? null)
                    .input('isCorrect',         sql.Bit,              evt.isCorrect ?? null)
                    .input('payloadJson',       sql.NVarChar(sql.MAX), evt.payloadJson ?? null)
                    .query(`
                        INSERT INTO app.training_session_events (
                            training_session_id, pod_device_id,
                            event_index, event_type, event_timestamp, elapsed_ms,
                            reaction_time_ms, is_correct, payload_json
                        )
                        VALUES (
                            @trainingSessionId, @podDeviceId,
                            @eventIndex, @eventType, @eventTimestamp, @elapsedMs,
                            @reactionTimeMs, @isCorrect, @payloadJson
                        )
                    `);
            }

            await transaction.commit();
            return session;
        } catch (err) {
            await transaction.rollback();
            throw err;
        }
    }

    // ── Find Single Session ───────────────────────────────────────────────────

    /**
     * Finds a non-deleted session by ID.
     */
    async findById(id: string): Promise<TrainingSessionRow | null> {
        const result = await this.pool
            .request()
            .input('id', sql.UniqueIdentifier, id)
            .query<TrainingSessionRow>(`
                SELECT
                    id, organization_id, device_kit_id, hub_device_id,
                    started_by_user_id, assigned_to_user_id, assigned_by_user_id, team_id,
                    origin, sync_status, client_session_id,
                    status, end_mode, preset_id, training_mode, config_json,
                    session_started_at, session_ended_at, duration_ms,
                    score, hit_count, miss_count, accuracy_percent,
                    avg_reaction_ms, best_reaction_ms, worst_reaction_ms,
                    active_pod_count, total_events_count, notes,
                    created_at, updated_at, deleted_at
                FROM app.training_sessions
                WHERE id = @id
                  AND deleted_at IS NULL
            `);
        return result.recordset[0] ?? null;
    }

    // ── List Sessions ─────────────────────────────────────────────────────────

    /**
a     * Visibility-aware session list.
     *
     * elevated=true  (org admin / trainer with session.start or session.assign):
     *   → all non-deleted sessions in the org, optional filter by assignee/team
     *
     * elevated=false (athlete / viewer):
     *   → only sessions where:
     *       - assigned_to_user_id = actorUserId   (assigned to me)
     *       - started_by_user_id  = actorUserId   (started by me)
     *       - assigned_to_user_id is in viewer_access_scopes for this actor/org
     *
     * isSuperAdmin=true:
     *   → all non-deleted sessions, optional org / assignee / team filters
     *
     * Always paginates: OFFSET @offset ROWS FETCH NEXT @limit ROWS ONLY
     */
    async findSessions(opts: {
        organizationId?: string;
        actorUserId?: string;
        elevated?: boolean;
        isSuperAdmin?: boolean;
        assignedToUserId?: string;
        teamId?: string;
        limit: number;
        offset: number;
    }): Promise<TrainingSessionRow[]> {
        const req = this.pool.request();
        req.input('limit',  sql.Int, opts.limit);
        req.input('offset', sql.Int, opts.offset);

        const baseCols = `
            ts.id, ts.organization_id, ts.device_kit_id, ts.hub_device_id,
            ts.started_by_user_id, ts.assigned_to_user_id, ts.assigned_by_user_id, ts.team_id,
            ts.origin, ts.sync_status, ts.client_session_id,
            ts.status, ts.end_mode, ts.preset_id, ts.training_mode, ts.config_json,
            ts.session_started_at, ts.session_ended_at, ts.duration_ms,
            ts.score, ts.hit_count, ts.miss_count, ts.accuracy_percent,
            ts.avg_reaction_ms, ts.best_reaction_ms, ts.worst_reaction_ms,
            ts.active_pod_count, ts.total_events_count, ts.notes,
            ts.created_at, ts.updated_at, ts.deleted_at
        `;
        const pagination = `ORDER BY ts.session_started_at DESC
            OFFSET @offset ROWS FETCH NEXT @limit ROWS ONLY`;

        const conditions: string[] = ['ts.deleted_at IS NULL'];

        if (opts.organizationId) {
            req.input('organizationId', sql.UniqueIdentifier, opts.organizationId);
            conditions.push('ts.organization_id = @organizationId');
        }
        if (opts.assignedToUserId) {
            req.input('assignedToUserId', sql.UniqueIdentifier, opts.assignedToUserId);
            conditions.push('ts.assigned_to_user_id = @assignedToUserId');
        }
        if (opts.teamId) {
            req.input('teamId', sql.UniqueIdentifier, opts.teamId);
            conditions.push('ts.team_id = @teamId');
        }

        let visibilityClause = '';

        if (!opts.isSuperAdmin && !opts.elevated) {
            // Athlete / Viewer: restrict to own or viewer-scoped sessions
            req.input('actorUserId', sql.UniqueIdentifier, opts.actorUserId!);
            req.input('actorOrgId',  sql.UniqueIdentifier, opts.organizationId!);
            visibilityClause = `
                AND (
                    ts.assigned_to_user_id = @actorUserId
                    OR ts.started_by_user_id = @actorUserId
                    OR ts.assigned_to_user_id IN (
                        SELECT vas.target_user_id
                        FROM app.viewer_access_scopes vas
                        WHERE vas.organization_id = @actorOrgId
                          AND vas.viewer_user_id  = @actorUserId
                    )
                )
            `;
        }

        const where = conditions.join(' AND ');
        const query = `
            SELECT ${baseCols}
            FROM app.training_sessions ts
            WHERE ${where}
            ${visibilityClause}
            ${pagination}
        `;

        const result = await req.query<TrainingSessionRow>(query);
        return result.recordset;
    }

    // ── Sub-resources ─────────────────────────────────────────────────────────

    async findActivePodsBySessionId(
        sessionId: string
    ): Promise<TrainingSessionActivePodRow[]> {
        const result = await this.pool
            .request()
            .input('sessionId', sql.UniqueIdentifier, sessionId)
            .query<TrainingSessionActivePodRow>(`
                SELECT id, training_session_id, pod_device_id, pod_order
                FROM app.training_session_active_pods
                WHERE training_session_id = @sessionId
                ORDER BY pod_order ASC, id ASC
            `);
        return result.recordset;
    }

    async findEventsBySessionId(
        sessionId: string
    ): Promise<TrainingSessionEventRow[]> {
        const result = await this.pool
            .request()
            .input('sessionId', sql.UniqueIdentifier, sessionId)
            .query<TrainingSessionEventRow>(`
                SELECT
                    id, training_session_id, pod_device_id,
                    event_index, event_type, event_timestamp, elapsed_ms,
                    reaction_time_ms, is_correct, payload_json, created_at
                FROM app.training_session_events
                WHERE training_session_id = @sessionId
                ORDER BY event_index ASC
            `);
        return result.recordset;
    }

    // ── Assign ────────────────────────────────────────────────────────────────

    async updateAssignment(
        id: string,
        data: UpdateAssignmentData
    ): Promise<TrainingSessionRow> {
        const result = await this.pool
            .request()
            .input('id',               sql.UniqueIdentifier, id)
            .input('assignedToUserId', sql.UniqueIdentifier, data.assignedToUserId ?? null)
            .input('teamId',           sql.UniqueIdentifier, data.teamId ?? null)
            .input('assignedByUserId', sql.UniqueIdentifier, data.assignedByUserId)
            .query<TrainingSessionRow>(`
                UPDATE app.training_sessions
                SET
                    assigned_to_user_id = @assignedToUserId,
                    team_id             = @teamId,
                    assigned_by_user_id = @assignedByUserId,
                    updated_at          = SYSUTCDATETIME()
                OUTPUT
                    INSERTED.id, INSERTED.organization_id, INSERTED.device_kit_id, INSERTED.hub_device_id,
                    INSERTED.started_by_user_id, INSERTED.assigned_to_user_id, INSERTED.assigned_by_user_id, INSERTED.team_id,
                    INSERTED.origin, INSERTED.sync_status, INSERTED.client_session_id,
                    INSERTED.status, INSERTED.end_mode, INSERTED.preset_id, INSERTED.training_mode, INSERTED.config_json,
                    INSERTED.session_started_at, INSERTED.session_ended_at, INSERTED.duration_ms,
                    INSERTED.score, INSERTED.hit_count, INSERTED.miss_count, INSERTED.accuracy_percent,
                    INSERTED.avg_reaction_ms, INSERTED.best_reaction_ms, INSERTED.worst_reaction_ms,
                    INSERTED.active_pod_count, INSERTED.total_events_count, INSERTED.notes,
                    INSERTED.created_at, INSERTED.updated_at, INSERTED.deleted_at
                WHERE id = @id
                  AND deleted_at IS NULL
            `);
        return result.recordset[0];
    }

    // ── Soft Delete + Audit ───────────────────────────────────────────────────

    /**
     * Soft-deletes a session and writes an audit log entry in a single transaction.
     */
    async softDelete(
        id: string,
        actorUserId: string,
        organizationId: string
    ): Promise<void> {
        const transaction = new sql.Transaction(this.pool);
        await transaction.begin();

        try {
            await transaction
                .request()
                .input('id', sql.UniqueIdentifier, id)
                .query(`
                    UPDATE app.training_sessions
                    SET deleted_at = SYSUTCDATETIME(),
                        updated_at = SYSUTCDATETIME()
                    WHERE id = @id
                      AND deleted_at IS NULL
                `);

            await transaction
                .request()
                .input('actorUserId',    sql.UniqueIdentifier, actorUserId)
                .input('organizationId', sql.UniqueIdentifier, organizationId)
                .input('entityId',       sql.UniqueIdentifier, id)
                .input('detailsJson',    sql.NVarChar(sql.MAX), JSON.stringify({ sessionId: id }))
                .query(`
                    INSERT INTO app.audit_logs
                        (actor_user_id, organization_id, entity_type, entity_id, action, details_json)
                    VALUES
                        (@actorUserId, @organizationId, N'training_session', @entityId, N'session.delete', @detailsJson)
                `);

            await transaction.commit();
        } catch (err) {
            await transaction.rollback();
            throw err;
        }
    }

    // ── Cross-org Validation Helpers ──────────────────────────────────────────

    /**
     * Returns true if the given hub belongs to the specified device kit.
     */
    async hubBelongsToKit(hubDeviceId: string, deviceKitId: string): Promise<boolean> {
        const result = await this.pool
            .request()
            .input('hubDeviceId', sql.UniqueIdentifier, hubDeviceId)
            .input('deviceKitId', sql.UniqueIdentifier, deviceKitId)
            .query<{ n: number }>(`
                SELECT COUNT(1) AS n
                FROM app.hub_devices
                WHERE id = @hubDeviceId
                  AND device_kit_id = @deviceKitId
            `);
        return (result.recordset[0]?.n ?? 0) > 0;
    }

    /**
     * Returns true if the given pod is currently assigned to the specified kit.
     */
    async podBelongsToKit(podDeviceId: string, deviceKitId: string): Promise<boolean> {
        const result = await this.pool
            .request()
            .input('podDeviceId', sql.UniqueIdentifier, podDeviceId)
            .input('deviceKitId', sql.UniqueIdentifier, deviceKitId)
            .query<{ n: number }>(`
                SELECT COUNT(1) AS n
                FROM app.pod_devices
                WHERE id = @podDeviceId
                  AND current_device_kit_id = @deviceKitId
            `);
        return (result.recordset[0]?.n ?? 0) > 0;
    }

    /**
     * Returns true if the team belongs to the specified organization and is not deleted.
     */
    async teamBelongsToOrg(teamId: string, organizationId: string): Promise<boolean> {
        const result = await this.pool
            .request()
            .input('teamId',         sql.UniqueIdentifier, teamId)
            .input('organizationId', sql.UniqueIdentifier, organizationId)
            .query<{ n: number }>(`
                SELECT COUNT(1) AS n
                FROM app.teams
                WHERE id = @teamId
                  AND organization_id = @organizationId
                  AND deleted_at IS NULL
            `);
        return (result.recordset[0]?.n ?? 0) > 0;
    }

    /**
     * Returns true if the user is an active member of the specified organization.
     */
    async userIsActiveMember(userId: string, organizationId: string): Promise<boolean> {
        const result = await this.pool
            .request()
            .input('userId',         sql.UniqueIdentifier, userId)
            .input('organizationId', sql.UniqueIdentifier, organizationId)
            .query<{ n: number }>(`
                SELECT COUNT(1) AS n
                FROM app.organization_memberships
                WHERE user_id        = @userId
                  AND organization_id = @organizationId
                  AND status          = N'ACTIVE'
                  AND left_at         IS NULL
            `);
        return (result.recordset[0]?.n ?? 0) > 0;
    }

    /**
     * Returns true if viewerUserId has an explicit viewer_access_scope grant
     * for targetUserId within the organization.
     */
    async viewerHasScope(
        organizationId: string,
        viewerUserId: string,
        targetUserId: string
    ): Promise<boolean> {
        const result = await this.pool
            .request()
            .input('organizationId', sql.UniqueIdentifier, organizationId)
            .input('viewerUserId',   sql.UniqueIdentifier, viewerUserId)
            .input('targetUserId',   sql.UniqueIdentifier, targetUserId)
            .query<{ n: number }>(`
                SELECT COUNT(1) AS n
                FROM app.viewer_access_scopes
                WHERE organization_id = @organizationId
                  AND viewer_user_id  = @viewerUserId
                  AND target_user_id  = @targetUserId
            `);
        return (result.recordset[0]?.n ?? 0) > 0;
    }
}

import sql from 'mssql';
import {
    TrainingSessionRow,
    TrainingSessionActivePodRow,
    TrainingSessionEventRow,
    ListSessionsFilters,
} from './sessions.types.js';

export interface CreateSessionData {
    id: string;
    organizationId: string;
    deviceKitId: string;
    hubDeviceId?: string;

    startedByUserId?: string;
    assignedToUserId?: string;
    teamId?: string;

    origin: string;
    clientSessionId: string;
    status: string;
    endMode: string;
    presetId?: string;
    trainingMode: string;
    configJson: string; // pre-serialised JSON string

    sessionStartedAt: Date;
    sessionEndedAt: Date;
    durationMs: number;

    score?: number;
    hitCount: number;
    missCount: number;
    accuracyPercent?: number;

    avgReactionMs?: number;
    bestReactionMs?: number;
    worstReactionMs?: number;

    activePodCount: number;
    totalEventsCount: number;
    notes?: string;
}

export interface CreateActivePodData {
    trainingSessionId: string;
    podDeviceId: string;
    podOrder?: number;
}

export interface CreateEventData {
    trainingSessionId: string;
    podDeviceId?: string;
    eventIndex: number;
    eventType: string;
    eventTimestamp: Date;
    elapsedMs?: number;
    reactionTimeMs?: number;
    isCorrect?: boolean;
    payloadJson?: string; // pre-serialised JSON string
}

export interface UpdateAssignmentData {
    assignedToUserId?: string | null;
    teamId?: string | null;
    assignedByUserId: string;
}

export class SessionsRepository {
    constructor(private readonly pool: sql.ConnectionPool) {}

    // ── Idempotency Check ─────────────────────────────────────────────────────

    /**
     * Returns an existing session if it was already synced with the same
     * (organization_id, client_session_id) pair. Includes deleted sessions
     * so re-sync of a deleted session is properly detected.
     */
    async findByClientSessionId(
        organizationId: string,
        clientSessionId: string
    ): Promise<TrainingSessionRow | null> {
        const result = await this.pool
            .request()
            .input('organizationId',  sql.UniqueIdentifier, organizationId)
            .input('clientSessionId', sql.NVarChar(100),     clientSessionId)
            .query<TrainingSessionRow>(`
                SELECT
                    id, organization_id, device_kit_id, hub_device_id,
                    started_by_user_id, assigned_to_user_id, assigned_by_user_id, team_id,
                    origin, sync_status, client_session_id,
                    status, end_mode, preset_id, training_mode, config_json,
                    session_started_at, session_ended_at, duration_ms,
                    score, hit_count, miss_count, accuracy_percent,
                    avg_reaction_ms, best_reaction_ms, worst_reaction_ms,
                    active_pod_count, total_events_count, notes,
                    created_at, updated_at, deleted_at
                FROM app.training_sessions
                WHERE organization_id   = @organizationId
                  AND client_session_id = @clientSessionId
            `);
        return result.recordset[0] ?? null;
    }

    // ── Sync (transactional) ──────────────────────────────────────────────────

    /**
     * Inserts session + active pods + events in a single transaction.
     * Caller must ensure idempotency check has already run.
     */
    async syncSession(
        sessionData: CreateSessionData,
        pods: CreateActivePodData[],
        events: CreateEventData[]
    ): Promise<TrainingSessionRow> {
        const transaction = new sql.Transaction(this.pool);
        await transaction.begin();

        try {
            // 1. Insert session row
            const sessionResult = await transaction
                .request()
                .input('id',               sql.UniqueIdentifier, sessionData.id)
                .input('organizationId',   sql.UniqueIdentifier, sessionData.organizationId)
                .input('deviceKitId',      sql.UniqueIdentifier, sessionData.deviceKitId)
                .input('hubDeviceId',      sql.UniqueIdentifier, sessionData.hubDeviceId ?? null)
                .input('startedByUserId',  sql.UniqueIdentifier, sessionData.startedByUserId ?? null)
                .input('assignedToUserId', sql.UniqueIdentifier, sessionData.assignedToUserId ?? null)
                .input('teamId',           sql.UniqueIdentifier, sessionData.teamId ?? null)
                .input('origin',           sql.NVarChar(20),     sessionData.origin)
                .input('clientSessionId',  sql.NVarChar(100),    sessionData.clientSessionId)
                .input('status',           sql.NVarChar(20),     sessionData.status)
                .input('endMode',          sql.NVarChar(20),     sessionData.endMode)
                .input('presetId',         sql.UniqueIdentifier, sessionData.presetId ?? null)
                .input('trainingMode',     sql.NVarChar(50),     sessionData.trainingMode)
                .input('configJson',       sql.NVarChar(sql.MAX), sessionData.configJson)
                .input('sessionStartedAt', sql.DateTime2,        sessionData.sessionStartedAt)
                .input('sessionEndedAt',   sql.DateTime2,        sessionData.sessionEndedAt)
                .input('durationMs',       sql.BigInt,           sessionData.durationMs)
                .input('score',            sql.Int,              sessionData.score ?? null)
                .input('hitCount',         sql.Int,              sessionData.hitCount)
                .input('missCount',        sql.Int,              sessionData.missCount)
                .input('accuracyPercent',  sql.Decimal(5, 2),    sessionData.accuracyPercent ?? null)
                .input('avgReactionMs',    sql.Decimal(10, 2),   sessionData.avgReactionMs ?? null)
                .input('bestReactionMs',   sql.Decimal(10, 2),   sessionData.bestReactionMs ?? null)
                .input('worstReactionMs',  sql.Decimal(10, 2),   sessionData.worstReactionMs ?? null)
                .input('activePodCount',   sql.Int,              sessionData.activePodCount)
                .input('totalEventsCount', sql.Int,              sessionData.totalEventsCount)
                .input('notes',            sql.NVarChar(1000),   sessionData.notes ?? null)
                .query<TrainingSessionRow>(`
                    INSERT INTO app.training_sessions (
                        id, organization_id, device_kit_id, hub_device_id,
                        started_by_user_id, assigned_to_user_id, team_id,
                        origin, sync_status, client_session_id,
                        status, end_mode, preset_id, training_mode, config_json,
                        session_started_at, session_ended_at, duration_ms,
                        score, hit_count, miss_count, accuracy_percent,
                        avg_reaction_ms, best_reaction_ms, worst_reaction_ms,
                        active_pod_count, total_events_count, notes
                    )
                    OUTPUT
                        INSERTED.id, INSERTED.organization_id, INSERTED.device_kit_id, INSERTED.hub_device_id,
                        INSERTED.started_by_user_id, INSERTED.assigned_to_user_id, INSERTED.assigned_by_user_id, INSERTED.team_id,
                        INSERTED.origin, INSERTED.sync_status, INSERTED.client_session_id,
                        INSERTED.status, INSERTED.end_mode, INSERTED.preset_id, INSERTED.training_mode, INSERTED.config_json,
                        INSERTED.session_started_at, INSERTED.session_ended_at, INSERTED.duration_ms,
                        INSERTED.score, INSERTED.hit_count, INSERTED.miss_count, INSERTED.accuracy_percent,
                        INSERTED.avg_reaction_ms, INSERTED.best_reaction_ms, INSERTED.worst_reaction_ms,
                        INSERTED.active_pod_count, INSERTED.total_events_count, INSERTED.notes,
                        INSERTED.created_at, INSERTED.updated_at, INSERTED.deleted_at
                    VALUES (
                        @id, @organizationId, @deviceKitId, @hubDeviceId,
                        @startedByUserId, @assignedToUserId, @teamId,
                        @origin, N'SYNCED', @clientSessionId,
                        @status, @endMode, @presetId, @trainingMode, @configJson,
                        @sessionStartedAt, @sessionEndedAt, @durationMs,
                        @score, @hitCount, @missCount, @accuracyPercent,
                        @avgReactionMs, @bestReactionMs, @worstReactionMs,
                        @activePodCount, @totalEventsCount, @notes
                    )
                `);

            const session = sessionResult.recordset[0];

            // 2. Insert active pods
            for (const pod of pods) {
                await transaction
                    .request()
                    .input('trainingSessionId', sql.UniqueIdentifier, pod.trainingSessionId)
                    .input('podDeviceId',       sql.UniqueIdentifier, pod.podDeviceId)
                    .input('podOrder',          sql.Int,              pod.podOrder ?? null)
                    .query(`
                        INSERT INTO app.training_session_active_pods
                            (training_session_id, pod_device_id, pod_order)
                        VALUES (@trainingSessionId, @podDeviceId, @podOrder)
                    `);
            }

            // 3. Insert events
            for (const evt of events) {
                await transaction
                    .request()
                    .input('trainingSessionId', sql.UniqueIdentifier, evt.trainingSessionId)
                    .input('podDeviceId',       sql.UniqueIdentifier, evt.podDeviceId ?? null)
                    .input('eventIndex',        sql.Int,              evt.eventIndex)
                    .input('eventType',         sql.NVarChar(50),     evt.eventType)
                    .input('eventTimestamp',    sql.DateTime2,        evt.eventTimestamp)
                    .input('elapsedMs',         sql.BigInt,           evt.elapsedMs ?? null)
                    .input('reactionTimeMs',    sql.Decimal(10, 2),   evt.reactionTimeMs ?? null)
                    .input('isCorrect',         sql.Bit,              evt.isCorrect ?? null)
                    .input('payloadJson',       sql.NVarChar(sql.MAX), evt.payloadJson ?? null)
                    .query(`
                        INSERT INTO app.training_session_events (
                            training_session_id, pod_device_id,
                            event_index, event_type, event_timestamp, elapsed_ms,
                            reaction_time_ms, is_correct, payload_json
                        )
                        VALUES (
                            @trainingSessionId, @podDeviceId,
                            @eventIndex, @eventType, @eventTimestamp, @elapsedMs,
                            @reactionTimeMs, @isCorrect, @payloadJson
                        )
                    `);
            }

            await transaction.commit();
            return session;
        } catch (err) {
            await transaction.rollback();
            throw err;
        }
    }

    // ── Find Single Session ───────────────────────────────────────────────────

    /**
     * Finds a non-deleted session by ID.
     */
    async findById(id: string): Promise<TrainingSessionRow | null> {
        const result = await this.pool
            .request()
            .input('id', sql.UniqueIdentifier, id)
            .query<TrainingSessionRow>(`
                SELECT
                    id, organization_id, device_kit_id, hub_device_id,
                    started_by_user_id, assigned_to_user_id, assigned_by_user_id, team_id,
                    origin, sync_status, client_session_id,
                    status, end_mode, preset_id, training_mode, config_json,
                    session_started_at, session_ended_at, duration_ms,
                    score, hit_count, miss_count, accuracy_percent,
                    avg_reaction_ms, best_reaction_ms, worst_reaction_ms,
                    active_pod_count, total_events_count, notes,
                    created_at, updated_at, deleted_at
                FROM app.training_sessions
                WHERE id = @id
                  AND deleted_at IS NULL
            `);
        return result.recordset[0] ?? null;
    }

    // ── List Sessions ─────────────────────────────────────────────────────────

    /**
a     * Visibility-aware session list.
     *
     * elevated=true  (org admin / trainer with session.start or session.assign):
     *   → all non-deleted sessions in the org, optional filter by assignee/team
     *
     * elevated=false (athlete / viewer):
     *   → only sessions where:
     *       - assigned_to_user_id = actorUserId   (assigned to me)
     *       - started_by_user_id  = actorUserId   (started by me)
     *       - assigned_to_user_id is in viewer_access_scopes for this actor/org
     *
     * isSuperAdmin=true:
     *   → all non-deleted sessions, optional org / assignee / team filters
     *
     * Always paginates: OFFSET @offset ROWS FETCH NEXT @limit ROWS ONLY
     */
    async findSessions(opts: {
        organizationId?: string;
        actorUserId?: string;
        elevated?: boolean;
        isSuperAdmin?: boolean;
        assignedToUserId?: string;
        teamId?: string;
        limit: number;
        offset: number;
    }): Promise<TrainingSessionRow[]> {
        const req = this.pool.request();
        req.input('limit',  sql.Int, opts.limit);
        req.input('offset', sql.Int, opts.offset);

        const baseCols = `
            ts.id, ts.organization_id, ts.device_kit_id, ts.hub_device_id,
            ts.started_by_user_id, ts.assigned_to_user_id, ts.assigned_by_user_id, ts.team_id,
            ts.origin, ts.sync_status, ts.client_session_id,
            ts.status, ts.end_mode, ts.preset_id, ts.training_mode, ts.config_json,
            ts.session_started_at, ts.session_ended_at, ts.duration_ms,
            ts.score, ts.hit_count, ts.miss_count, ts.accuracy_percent,
            ts.avg_reaction_ms, ts.best_reaction_ms, ts.worst_reaction_ms,
            ts.active_pod_count, ts.total_events_count, ts.notes,
            ts.created_at, ts.updated_at, ts.deleted_at
        `;
        const pagination = `ORDER BY ts.session_started_at DESC
            OFFSET @offset ROWS FETCH NEXT @limit ROWS ONLY`;

        const conditions: string[] = ['ts.deleted_at IS NULL'];

        if (opts.organizationId) {
            req.input('organizationId', sql.UniqueIdentifier, opts.organizationId);
            conditions.push('ts.organization_id = @organizationId');
        }
        if (opts.assignedToUserId) {
            req.input('assignedToUserId', sql.UniqueIdentifier, opts.assignedToUserId);
            conditions.push('ts.assigned_to_user_id = @assignedToUserId');
        }
        if (opts.teamId) {
            req.input('teamId', sql.UniqueIdentifier, opts.teamId);
            conditions.push('ts.team_id = @teamId');
        }

        let visibilityClause = '';

        if (!opts.isSuperAdmin && !opts.elevated) {
            // Athlete / Viewer: restrict to own or viewer-scoped sessions
            req.input('actorUserId', sql.UniqueIdentifier, opts.actorUserId!);
            req.input('actorOrgId',  sql.UniqueIdentifier, opts.organizationId!);
            visibilityClause = `
                AND (
                    ts.assigned_to_user_id = @actorUserId
                    OR ts.started_by_user_id = @actorUserId
                    OR ts.assigned_to_user_id IN (
                        SELECT vas.target_user_id
                        FROM app.viewer_access_scopes vas
                        WHERE vas.organization_id = @actorOrgId
                          AND vas.viewer_user_id  = @actorUserId
                    )
                )
            `;
        }

        const where = conditions.join(' AND ');
        const query = `
            SELECT ${baseCols}
            FROM app.training_sessions ts
            WHERE ${where}
            ${visibilityClause}
            ${pagination}
        `;

        const result = await req.query<TrainingSessionRow>(query);
        return result.recordset;
    }

    /**
     * Returns the total count of sessions matching the same filters and visibility
     * as findSessions(), without pagination.  Run in parallel with findSessions().
     */
    async countSessions(opts: {
        organizationId?: string;
        actorUserId?: string;
        elevated?: boolean;
        isSuperAdmin?: boolean;
        assignedToUserId?: string;
        teamId?: string;
    }): Promise<number> {
        const req = this.pool.request();

        const conditions: string[] = ['ts.deleted_at IS NULL'];

        if (opts.organizationId) {
            req.input('organizationId', sql.UniqueIdentifier, opts.organizationId);
            conditions.push('ts.organization_id = @organizationId');
        }
        if (opts.assignedToUserId) {
            req.input('assignedToUserId', sql.UniqueIdentifier, opts.assignedToUserId);
            conditions.push('ts.assigned_to_user_id = @assignedToUserId');
        }
        if (opts.teamId) {
            req.input('teamId', sql.UniqueIdentifier, opts.teamId);
            conditions.push('ts.team_id = @teamId');
        }

        let visibilityClause = '';

        if (!opts.isSuperAdmin && !opts.elevated) {
            req.input('actorUserId', sql.UniqueIdentifier, opts.actorUserId!);
            req.input('actorOrgId',  sql.UniqueIdentifier, opts.organizationId!);
            visibilityClause = `
                AND (
                    ts.assigned_to_user_id = @actorUserId
                    OR ts.started_by_user_id = @actorUserId
                    OR ts.assigned_to_user_id IN (
                        SELECT vas.target_user_id
                        FROM app.viewer_access_scopes vas
                        WHERE vas.organization_id = @actorOrgId
                          AND vas.viewer_user_id  = @actorUserId
                    )
                )
            `;
        }

        const where = conditions.join(' AND ');
        const result = await req.query<{ total: number }>(`
            SELECT COUNT(1) AS total
            FROM app.training_sessions ts
            WHERE ${where}
            ${visibilityClause}
        `);

        return result.recordset[0]?.total ?? 0;
    }

    // ── Sub-resources ─────────────────────────────────────────────────────────

    async findActivePodsBySessionId(
        sessionId: string
    ): Promise<TrainingSessionActivePodRow[]> {
        const result = await this.pool
            .request()
            .input('sessionId', sql.UniqueIdentifier, sessionId)
            .query<TrainingSessionActivePodRow>(`
                SELECT id, training_session_id, pod_device_id, pod_order
                FROM app.training_session_active_pods
                WHERE training_session_id = @sessionId
                ORDER BY pod_order ASC, id ASC
            `);
        return result.recordset;
    }

    async findEventsBySessionId(
        sessionId: string
    ): Promise<TrainingSessionEventRow[]> {
        const result = await this.pool
            .request()
            .input('sessionId', sql.UniqueIdentifier, sessionId)
            .query<TrainingSessionEventRow>(`
                SELECT
                    id, training_session_id, pod_device_id,
                    event_index, event_type, event_timestamp, elapsed_ms,
                    reaction_time_ms, is_correct, payload_json, created_at
                FROM app.training_session_events
                WHERE training_session_id = @sessionId
                ORDER BY event_index ASC
            `);
        return result.recordset;
    }

    // ── Assign ────────────────────────────────────────────────────────────────

    async updateAssignment(
        id: string,
        data: UpdateAssignmentData
    ): Promise<TrainingSessionRow> {
        const result = await this.pool
            .request()
            .input('id',               sql.UniqueIdentifier, id)
            .input('assignedToUserId', sql.UniqueIdentifier, data.assignedToUserId ?? null)
            .input('teamId',           sql.UniqueIdentifier, data.teamId ?? null)
            .input('assignedByUserId', sql.UniqueIdentifier, data.assignedByUserId)
            .query<TrainingSessionRow>(`
                UPDATE app.training_sessions
                SET
                    assigned_to_user_id = @assignedToUserId,
                    team_id             = @teamId,
                    assigned_by_user_id = @assignedByUserId,
                    updated_at          = SYSUTCDATETIME()
                OUTPUT
                    INSERTED.id, INSERTED.organization_id, INSERTED.device_kit_id, INSERTED.hub_device_id,
                    INSERTED.started_by_user_id, INSERTED.assigned_to_user_id, INSERTED.assigned_by_user_id, INSERTED.team_id,
                    INSERTED.origin, INSERTED.sync_status, INSERTED.client_session_id,
                    INSERTED.status, INSERTED.end_mode, INSERTED.preset_id, INSERTED.training_mode, INSERTED.config_json,
                    INSERTED.session_started_at, INSERTED.session_ended_at, INSERTED.duration_ms,
                    INSERTED.score, INSERTED.hit_count, INSERTED.miss_count, INSERTED.accuracy_percent,
                    INSERTED.avg_reaction_ms, INSERTED.best_reaction_ms, INSERTED.worst_reaction_ms,
                    INSERTED.active_pod_count, INSERTED.total_events_count, INSERTED.notes,
                    INSERTED.created_at, INSERTED.updated_at, INSERTED.deleted_at
                WHERE id = @id
                  AND deleted_at IS NULL
            `);
        return result.recordset[0];
    }

    // ── Soft Delete + Audit ───────────────────────────────────────────────────

    /**
     * Soft-deletes a session and writes an audit log entry in a single transaction.
     */
    async softDelete(
        id: string,
        actorUserId: string,
        organizationId: string
    ): Promise<void> {
        const transaction = new sql.Transaction(this.pool);
        await transaction.begin();

        try {
            await transaction
                .request()
                .input('id', sql.UniqueIdentifier, id)
                .query(`
                    UPDATE app.training_sessions
                    SET deleted_at = SYSUTCDATETIME(),
                        updated_at = SYSUTCDATETIME()
                    WHERE id = @id
                      AND deleted_at IS NULL
                `);

            await transaction
                .request()
                .input('actorUserId',    sql.UniqueIdentifier, actorUserId)
                .input('organizationId', sql.UniqueIdentifier, organizationId)
                .input('entityId',       sql.UniqueIdentifier, id)
                .input('detailsJson',    sql.NVarChar(sql.MAX), JSON.stringify({ sessionId: id }))
                .query(`
                    INSERT INTO app.audit_logs
                        (actor_user_id, organization_id, entity_type, entity_id, action, details_json)
                    VALUES
                        (@actorUserId, @organizationId, N'training_session', @entityId, N'session.delete', @detailsJson)
                `);

            await transaction.commit();
        } catch (err) {
            await transaction.rollback();
            throw err;
        }
    }

    // ── Cross-org Validation Helpers ──────────────────────────────────────────

    /**
     * Returns true if the given hub belongs to the specified device kit.
     */
    async hubBelongsToKit(hubDeviceId: string, deviceKitId: string): Promise<boolean> {
        const result = await this.pool
            .request()
            .input('hubDeviceId', sql.UniqueIdentifier, hubDeviceId)
            .input('deviceKitId', sql.UniqueIdentifier, deviceKitId)
            .query<{ n: number }>(`
                SELECT COUNT(1) AS n
                FROM app.hub_devices
                WHERE id = @hubDeviceId
                  AND device_kit_id = @deviceKitId
            `);
        return (result.recordset[0]?.n ?? 0) > 0;
    }

    /**
     * Returns true if the given pod is currently assigned to the specified kit.
     */
    async podBelongsToKit(podDeviceId: string, deviceKitId: string): Promise<boolean> {
        const result = await this.pool
            .request()
            .input('podDeviceId', sql.UniqueIdentifier, podDeviceId)
            .input('deviceKitId', sql.UniqueIdentifier, deviceKitId)
            .query<{ n: number }>(`
                SELECT COUNT(1) AS n
                FROM app.pod_devices
                WHERE id = @podDeviceId
                  AND current_device_kit_id = @deviceKitId
            `);
        return (result.recordset[0]?.n ?? 0) > 0;
    }

    /**
     * Returns true if the team belongs to the specified organization and is not deleted.
     */
    async teamBelongsToOrg(teamId: string, organizationId: string): Promise<boolean> {
        const result = await this.pool
            .request()
            .input('teamId',         sql.UniqueIdentifier, teamId)
            .input('organizationId', sql.UniqueIdentifier, organizationId)
            .query<{ n: number }>(`
                SELECT COUNT(1) AS n
                FROM app.teams
                WHERE id = @teamId
                  AND organization_id = @organizationId
                  AND deleted_at IS NULL
            `);
        return (result.recordset[0]?.n ?? 0) > 0;
    }

    /**
     * Returns true if the user is an active member of the specified organization.
     */
    async userIsActiveMember(userId: string, organizationId: string): Promise<boolean> {
        const result = await this.pool
            .request()
            .input('userId',         sql.UniqueIdentifier, userId)
            .input('organizationId', sql.UniqueIdentifier, organizationId)
            .query<{ n: number }>(`
                SELECT COUNT(1) AS n
                FROM app.organization_memberships
                WHERE user_id        = @userId
                  AND organization_id = @organizationId
                  AND status          = N'ACTIVE'
                  AND left_at         IS NULL
            `);
        return (result.recordset[0]?.n ?? 0) > 0;
    }

    /**
     * Returns true if viewerUserId has an explicit viewer_access_scope grant
     * for targetUserId within the organization.
     */
    async viewerHasScope(
        organizationId: string,
        viewerUserId: string,
        targetUserId: string
    ): Promise<boolean> {
        const result = await this.pool
            .request()
            .input('organizationId', sql.UniqueIdentifier, organizationId)
            .input('viewerUserId',   sql.UniqueIdentifier, viewerUserId)
            .input('targetUserId',   sql.UniqueIdentifier, targetUserId)
            .query<{ n: number }>(`
                SELECT COUNT(1) AS n
                FROM app.viewer_access_scopes
                WHERE organization_id = @organizationId
                  AND viewer_user_id  = @viewerUserId
                  AND target_user_id  = @targetUserId
            `);
        return (result.recordset[0]?.n ?? 0) > 0;
    }
}

import { randomUUID } from 'crypto';
import {
    ForbiddenError,
    NotFoundError,
} from '../../shared/errors/http-errors.js';
import { AuthUser } from '../../shared/types/auth-user.types.js';
import { OrganizationsRepository } from '../organizations/organizations.repository.js';
import { SessionsRepository } from './sessions.repository.js';
import {
    mapSessionSummary,
    mapSessionDetail,
} from './sessions.mapper.js';
import {
    SyncSessionInput,
    ListSessionsFilters,
    AssignSessionInput,
    SessionSummary,
    SessionDetail,
    TrainingSessionRow,
} from './sessions.types.js';

/** Permission codes that grant elevated session visibility (all org sessions). */
const ELEVATED_SESSION_PERMS = ['session.start', 'session.assign', 'session.end', 'session.delete'];

export class SessionsService {
    constructor(
        private readonly sessionsRepo: SessionsRepository,
        private readonly orgsRepo:     OrganizationsRepository
    ) {}

    // ── Sync Session ──────────────────────────────────────────────────────────

    /**
     * Accepts a completed offline session payload and persists it.
     *
     * Idempotency: if the same (organizationId, clientSessionId) already exists,
     * the existing record is returned with a 200 (not 201), so duplicate syncs
     * are safe and have no side effects.
     *
     * Cross-org validation:
     *   - hub (if provided) must belong to the specified kit
     *   - pods (if provided) must be currently assigned to that kit
     *   - assignedToUserId (if provided) must be an active org member
     *   - teamId (if provided) must belong to the same org
     */
    async syncSession(
        input: SyncSessionInput,
        actor: AuthUser
    ): Promise<{ session: SessionSummary; created: boolean }> {
        // Require active org membership to sync
        await this.requireActiveMember(input.organizationId, actor);

        // Idempotency check
        const existing = await this.sessionsRepo.findByClientSessionId(
            input.organizationId,
            input.clientSessionId
        );
        if (existing) {
            return { session: mapSessionSummary(existing), created: false };
        }

        // Cross-org: validate kit belongs to org
        const kit = await this.orgsRepo.findById(input.organizationId);
        if (!kit || !kit.is_active) {
            throw new NotFoundError('Organization not found or inactive.');
        }

        // Cross-org: validate hub belongs to kit (if provided)
        if (input.hubDeviceId) {
            const valid = await this.sessionsRepo.hubBelongsToKit(
                input.hubDeviceId,
                input.deviceKitId
            );
            if (!valid) {
                throw new NotFoundError(
                    'The specified hub does not belong to the specified device kit.'
                );
            }
        }

        // Cross-org: validate pods belong to kit (if provided)
        if (input.activePods && input.activePods.length > 0) {
            for (const pod of input.activePods) {
                const valid = await this.sessionsRepo.podBelongsToKit(
                    pod.podDeviceId,
                    input.deviceKitId
                );
                if (!valid) {
                    throw new NotFoundError(
                        `Pod ${pod.podDeviceId} does not belong to the specified device kit.`
                    );
                }
            }
        }

        // Cross-org: validate assignedToUserId is an active org member
        if (input.assignedToUserId) {
            const isMember = await this.sessionsRepo.userIsActiveMember(
                input.assignedToUserId,
                input.organizationId
            );
            if (!isMember) {
                throw new NotFoundError(
                    'The assigned user is not an active member of this organization.'
                );
            }
        }

        // Cross-org: validate teamId belongs to org
        if (input.teamId) {
            const valid = await this.sessionsRepo.teamBelongsToOrg(
                input.teamId,
                input.organizationId
            );
            if (!valid) {
                throw new NotFoundError(
                    'The specified team does not belong to this organization.'
                );
            }
        }

        const sessionId = randomUUID();

        const pods = (input.activePods ?? []).map(p => ({
            trainingSessionId: sessionId,
            podDeviceId: p.podDeviceId,
            podOrder: p.podOrder,
        }));

        const events = (input.events ?? []).map(e => ({
            trainingSessionId: sessionId,
            podDeviceId: e.podDeviceId,
            eventIndex: e.eventIndex,
            eventType: e.eventType,
            eventTimestamp: new Date(e.eventTimestamp),
            elapsedMs: e.elapsedMs,
            reactionTimeMs: e.reactionTimeMs,
            isCorrect: e.isCorrect,
            payloadJson: e.payloadJson ? JSON.stringify(e.payloadJson) : undefined,
        }));

        const row = await this.sessionsRepo.syncSession(
            {
                id:               sessionId,
                organizationId:   input.organizationId,
                deviceKitId:      input.deviceKitId,
                hubDeviceId:      input.hubDeviceId,
                startedByUserId:  input.startedByUserId,
                assignedToUserId: input.assignedToUserId,
                teamId:           input.teamId,
                origin:           input.origin,
                clientSessionId:  input.clientSessionId,
                status:           input.status,
                endMode:          input.endMode,
                presetId:         input.presetId,
                trainingMode:     input.trainingMode,
                configJson:       JSON.stringify(input.configJson),
                sessionStartedAt: new Date(input.sessionStartedAt),
                sessionEndedAt:   new Date(input.sessionEndedAt),
                durationMs:       input.durationMs,
                score:            input.score,
                hitCount:         input.hitCount,
                missCount:        input.missCount,
                accuracyPercent:  input.accuracyPercent,
                avgReactionMs:    input.avgReactionMs,
                bestReactionMs:   input.bestReactionMs,
                worstReactionMs:  input.worstReactionMs,
                activePodCount:   pods.length,
                totalEventsCount: events.length,
                notes:            input.notes,
            },
            pods,
            events
        );

        return { session: mapSessionSummary(row), created: true };
    }

    // ── List Sessions ─────────────────────────────────────────────────────────

    /**
     * Visibility rules:
     *   - Super admin:         all sessions (optional org/assignee/team filters)
     *   - Elevated member:     all sessions in org (has any session.* permission)
     *   - Restricted member:   only sessions assigned-to or started-by actor,
     *                          plus sessions assigned to viewer-scope targets
     *
     * organizationId is required for non-super-admins.
     */
    async listSessions(
        filters: ListSessionsFilters,
        actor: AuthUser
    ): Promise<SessionSummary[]> {
        if (!actor.isSuperAdmin) {
            if (!filters.organizationId) {
                throw new ForbiddenError('organizationId is required when listing sessions.');
            }
            await this.requireActiveMember(filters.organizationId, actor);
        }

        const elevated = actor.isSuperAdmin
            ? true
            : await this.isElevatedActor(filters.organizationId!, actor);

        const rows = await this.sessionsRepo.findSessions({
            organizationId:   filters.organizationId,
            actorUserId:      actor.userId,
            elevated,
            isSuperAdmin:     actor.isSuperAdmin,
            assignedToUserId: filters.assignedToUserId,
            teamId:           filters.teamId,
            limit:            filters.limit  ?? 50,
            offset:           filters.offset ?? 0,
        });

        return rows.map(mapSessionSummary);
    }

    // ── Get Session Detail ────────────────────────────────────────────────────

    /**
     * Returns full session detail including pods and events.
     * Enforces org-scoped visibility.
     */
    async getSessionDetail(
        sessionId: string,
        actor: AuthUser
    ): Promise<SessionDetail> {
        const row = await this.requireSessionExists(sessionId);
        await this.requireCanSeeSession(row, actor);

        const [pods, events] = await Promise.all([
            this.sessionsRepo.findActivePodsBySessionId(sessionId),
            this.sessionsRepo.findEventsBySessionId(sessionId),
        ]);

        return mapSessionDetail(row, pods, events);
    }

    // ── Assign Session ────────────────────────────────────────────────────────

    /**
     * Updates assignment fields (assignedToUserId, teamId) for a session.
     * Requires session.assign permission on the session's organization.
     * Validates that new assignee/team belong to the same org.
     */
    async assignSession(
        sessionId: string,
        input: AssignSessionInput,
        actor: AuthUser
    ): Promise<SessionSummary> {
        const row = await this.requireSessionExists(sessionId);
        await this.requirePermission(row.organization_id, actor, 'session.assign');

        // Validate new assignedToUserId is an active org member
        if (input.assignedToUserId) {
            const isMember = await this.sessionsRepo.userIsActiveMember(
                input.assignedToUserId,
                row.organization_id
            );
            if (!isMember) {
                throw new NotFoundError(
                    'The assigned user is not an active member of this organization.'
                );
            }
        }

        // Validate teamId belongs to same org
        if (input.teamId) {
            const valid = await this.sessionsRepo.teamBelongsToOrg(
                input.teamId,
                row.organization_id
            );
            if (!valid) {
                throw new NotFoundError(
                    'The specified team does not belong to this organization.'
                );
            }
        }

        const updated = await this.sessionsRepo.updateAssignment(sessionId, {
            assignedToUserId: input.assignedToUserId,
            teamId:           input.teamId,
            assignedByUserId: actor.userId,
        });

        return mapSessionSummary(updated);
    }

    // ── Delete Session ────────────────────────────────────────────────────────

    /**
     * Soft-deletes a session and writes an audit log entry.
     * Requires session.delete permission on the session's organization.
     * Repeated deletes are idempotent (no error if already deleted).
     */
    async deleteSession(sessionId: string, actor: AuthUser): Promise<void> {
        // Note: findById only returns non-deleted sessions.
        // If already deleted we treat it as idempotent (not found → already gone → OK).
        const row = await this.sessionsRepo.findById(sessionId);
        if (!row) {
            // Already deleted or never existed — idempotent, no error needed.
            return;
        }

        await this.requirePermission(row.organization_id, actor, 'session.delete');
        await this.sessionsRepo.softDelete(sessionId, actor.userId, row.organization_id);
    }

    // ── Private Helpers ───────────────────────────────────────────────────────

    private async requireSessionExists(sessionId: string): Promise<TrainingSessionRow> {
        const row = await this.sessionsRepo.findById(sessionId);
        if (!row) throw new NotFoundError('Session not found.');
        return row;
    }

    /**
     * Returns true if the actor holds any elevated session permission
     * (session.start, session.assign, session.end, session.delete).
     * These correspond to ORG_ADMIN / TRAINER level access.
     */
    private async isElevatedActor(organizationId: string, actor: AuthUser): Promise<boolean> {
        if (actor.isSuperAdmin) return true;
        const permissions = await this.orgsRepo.findEffectivePermissions(organizationId, actor.userId);
        return ELEVATED_SESSION_PERMS.some(p => permissions.includes(p));
    }

    /**
     * Enforces session-level visibility for GET detail.
     *
     * Super admin        → always passes
     * Elevated member    → passes for any session in their org
     * Restricted member  → passes only if:
     *     - assigned_to_user_id == actorUserId  (assigned to me)
     *     - started_by_user_id  == actorUserId  (started by me)
     *     - viewer_access_scopes grants actor visibility to assigned_to_user
     */
    private async requireCanSeeSession(
        row: TrainingSessionRow,
        actor: AuthUser
    ): Promise<void> {
        if (actor.isSuperAdmin) return;

        const membership = await this.orgsRepo.findMembership(row.organization_id, actor.userId);
        if (!membership || membership.status !== 'ACTIVE' || membership.left_at !== null) {
            throw new ForbiddenError('You do not have access to this session.');
        }

        const elevated = await this.isElevatedActor(row.organization_id, actor);
        if (elevated) return;

        // Self-access: assigned to me or started by me
        if (row.assigned_to_user_id === actor.userId) return;
        if (row.started_by_user_id  === actor.userId) return;

        // Viewer scope: actor has explicit visibility grant for the session's assignee
        if (row.assigned_to_user_id) {
            const hasScope = await this.sessionsRepo.viewerHasScope(
                row.organization_id,
                actor.userId,
                row.assigned_to_user_id
            );
            if (hasScope) return;
        }

        throw new ForbiddenError('You do not have access to this session.');
    }

    private async requireActiveMember(organizationId: string, actor: AuthUser): Promise<void> {
        if (actor.isSuperAdmin) return;
        const membership = await this.orgsRepo.findMembership(organizationId, actor.userId);
        if (!membership || membership.status !== 'ACTIVE' || membership.left_at !== null) {
            throw new ForbiddenError('You are not an active member of this organization.');
        }
    }

    private async requirePermission(
        organizationId: string,
        actor: AuthUser,
        permissionCode: string
    ): Promise<void> {
        if (actor.isSuperAdmin) return;

        const membership = await this.orgsRepo.findMembership(organizationId, actor.userId);
        if (!membership || membership.status !== 'ACTIVE' || membership.left_at !== null) {
            throw new ForbiddenError('You are not an active member of this organization.');
        }

        const permissions = await this.orgsRepo.findEffectivePermissions(organizationId, actor.userId);
        if (!permissions.includes(permissionCode)) {
            throw new ForbiddenError(`You do not have the required permission: ${permissionCode}`);
        }
    }
}

import { randomUUID } from 'crypto';
import {
    ForbiddenError,
    NotFoundError,
} from '../../shared/errors/http-errors.js';
import { AuthUser } from '../../shared/types/auth-user.types.js';
import { OrganizationsRepository } from '../organizations/organizations.repository.js';
import { SessionsRepository } from './sessions.repository.js';
import {
    mapSessionSummary,
    mapSessionDetail,
} from './sessions.mapper.js';
import {
    SyncSessionInput,
    ListSessionsFilters,
    AssignSessionInput,
    SessionSummary,
    SessionDetail,
    TrainingSessionRow,
    SessionListResult,
} from './sessions.types.js';

/** Permission codes that grant elevated session visibility (all org sessions). */
const ELEVATED_SESSION_PERMS = ['session.start', 'session.assign', 'session.end', 'session.delete'];

export class SessionsService {
    constructor(
        private readonly sessionsRepo: SessionsRepository,
        private readonly orgsRepo:     OrganizationsRepository
    ) {}

    // ── Sync Session ──────────────────────────────────────────────────────────

    /**
     * Accepts a completed offline session payload and persists it.
     *
     * Idempotency: if the same (organizationId, clientSessionId) already exists,
     * the existing record is returned with a 200 (not 201), so duplicate syncs
     * are safe and have no side effects.
     *
     * Cross-org validation:
     *   - hub (if provided) must belong to the specified kit
     *   - pods (if provided) must be currently assigned to that kit
     *   - assignedToUserId (if provided) must be an active org member
     *   - teamId (if provided) must belong to the same org
     */
    async syncSession(
        input: SyncSessionInput,
        actor: AuthUser
    ): Promise<{ session: SessionSummary; created: boolean }> {
        // Require active org membership to sync
        await this.requireActiveMember(input.organizationId, actor);

        // Idempotency check
        const existing = await this.sessionsRepo.findByClientSessionId(
            input.organizationId,
            input.clientSessionId
        );
        if (existing) {
            return { session: mapSessionSummary(existing), created: false };
        }

        // Cross-org: validate kit belongs to org
        const kit = await this.orgsRepo.findById(input.organizationId);
        if (!kit || !kit.is_active) {
            throw new NotFoundError('Organization not found or inactive.');
        }

        // Cross-org: validate hub belongs to kit (if provided)
        if (input.hubDeviceId) {
            const valid = await this.sessionsRepo.hubBelongsToKit(
                input.hubDeviceId,
                input.deviceKitId
            );
            if (!valid) {
                throw new NotFoundError(
                    'The specified hub does not belong to the specified device kit.'
                );
            }
        }

        // Cross-org: validate pods belong to kit (if provided)
        if (input.activePods && input.activePods.length > 0) {
            for (const pod of input.activePods) {
                const valid = await this.sessionsRepo.podBelongsToKit(
                    pod.podDeviceId,
                    input.deviceKitId
                );
                if (!valid) {
                    throw new NotFoundError(
                        `Pod ${pod.podDeviceId} does not belong to the specified device kit.`
                    );
                }
            }
        }

        // Cross-org: validate assignedToUserId is an active org member
        if (input.assignedToUserId) {
            const isMember = await this.sessionsRepo.userIsActiveMember(
                input.assignedToUserId,
                input.organizationId
            );
            if (!isMember) {
                throw new NotFoundError(
                    'The assigned user is not an active member of this organization.'
                );
            }
        }

        // Cross-org: validate teamId belongs to org
        if (input.teamId) {
            const valid = await this.sessionsRepo.teamBelongsToOrg(
                input.teamId,
                input.organizationId
            );
            if (!valid) {
                throw new NotFoundError(
                    'The specified team does not belong to this organization.'
                );
            }
        }

        const sessionId = randomUUID();

        const pods = (input.activePods ?? []).map(p => ({
            trainingSessionId: sessionId,
            podDeviceId: p.podDeviceId,
            podOrder: p.podOrder,
        }));

        const events = (input.events ?? []).map(e => ({
            trainingSessionId: sessionId,
            podDeviceId: e.podDeviceId,
            eventIndex: e.eventIndex,
            eventType: e.eventType,
            eventTimestamp: new Date(e.eventTimestamp),
            elapsedMs: e.elapsedMs,
            reactionTimeMs: e.reactionTimeMs,
            isCorrect: e.isCorrect,
            payloadJson: e.payloadJson ? JSON.stringify(e.payloadJson) : undefined,
        }));

        const row = await this.sessionsRepo.syncSession(
            {
                id:               sessionId,
                organizationId:   input.organizationId,
                deviceKitId:      input.deviceKitId,
                hubDeviceId:      input.hubDeviceId,
                startedByUserId:  input.startedByUserId,
                assignedToUserId: input.assignedToUserId,
                teamId:           input.teamId,
                origin:           input.origin,
                clientSessionId:  input.clientSessionId,
                status:           input.status,
                endMode:          input.endMode,
                presetId:         input.presetId,
                trainingMode:     input.trainingMode,
                configJson:       JSON.stringify(input.configJson),
                sessionStartedAt: new Date(input.sessionStartedAt),
                sessionEndedAt:   new Date(input.sessionEndedAt),
                durationMs:       input.durationMs,
                score:            input.score,
                hitCount:         input.hitCount,
                missCount:        input.missCount,
                accuracyPercent:  input.accuracyPercent,
                avgReactionMs:    input.avgReactionMs,
                bestReactionMs:   input.bestReactionMs,
                worstReactionMs:  input.worstReactionMs,
                activePodCount:   pods.length,
                totalEventsCount: events.length,
                notes:            input.notes,
            },
            pods,
            events
        );

        return { session: mapSessionSummary(row), created: true };
    }

    // ── List Sessions ─────────────────────────────────────────────────────────

    /**
     * Visibility rules:
     *   - Super admin:         all sessions (optional org/assignee/team filters)
     *   - Elevated member:     all sessions in org (has any session.* permission)
     *   - Restricted member:   only sessions assigned-to or started-by actor,
     *                          plus sessions assigned to viewer-scope targets
     *
     * organizationId is required for non-super-admins.
     */
    async listSessions(
        filters: ListSessionsFilters,
        actor: AuthUser
    ): Promise<SessionListResult> {
        if (!actor.isSuperAdmin) {
            if (!filters.organizationId) {
                throw new ForbiddenError('organizationId is required when listing sessions.');
            }
            await this.requireActiveMember(filters.organizationId, actor);
        }

        const elevated = actor.isSuperAdmin
            ? true
            : await this.isElevatedActor(filters.organizationId!, actor);

        const limit  = filters.limit  ?? 50;
        const offset = filters.offset ?? 0;

        const queryOpts = {
            organizationId:   filters.organizationId,
            actorUserId:      actor.userId,
            elevated,
            isSuperAdmin:     actor.isSuperAdmin,
            assignedToUserId: filters.assignedToUserId,
            teamId:           filters.teamId,
        };

        const [rows, total] = await Promise.all([
            this.sessionsRepo.findSessions({ ...queryOpts, limit, offset }),
            this.sessionsRepo.countSessions(queryOpts),
        ]);

        return { sessions: rows.map(mapSessionSummary), total, limit, offset };
    }

    // ── Get Session Detail ────────────────────────────────────────────────────

    /**
     * Returns full session detail including pods and events.
     * Enforces org-scoped visibility.
     */
    async getSessionDetail(
        sessionId: string,
        actor: AuthUser
    ): Promise<SessionDetail> {
        const row = await this.requireSessionExists(sessionId);
        await this.requireCanSeeSession(row, actor);

        const [pods, events] = await Promise.all([
            this.sessionsRepo.findActivePodsBySessionId(sessionId),
            this.sessionsRepo.findEventsBySessionId(sessionId),
        ]);

        return mapSessionDetail(row, pods, events);
    }

    // ── Assign Session ────────────────────────────────────────────────────────

    /**
     * Updates assignment fields (assignedToUserId, teamId) for a session.
     * Requires session.assign permission on the session's organization.
     * Validates that new assignee/team belong to the same org.
     */
    async assignSession(
        sessionId: string,
        input: AssignSessionInput,
        actor: AuthUser
    ): Promise<SessionSummary> {
        const row = await this.requireSessionExists(sessionId);
        await this.requirePermission(row.organization_id, actor, 'session.assign');

        // Validate new assignedToUserId is an active org member
        if (input.assignedToUserId) {
            const isMember = await this.sessionsRepo.userIsActiveMember(
                input.assignedToUserId,
                row.organization_id
            );
            if (!isMember) {
                throw new NotFoundError(
                    'The assigned user is not an active member of this organization.'
                );
            }
        }

        // Validate teamId belongs to same org
        if (input.teamId) {
            const valid = await this.sessionsRepo.teamBelongsToOrg(
                input.teamId,
                row.organization_id
            );
            if (!valid) {
                throw new NotFoundError(
                    'The specified team does not belong to this organization.'
                );
            }
        }

        const updated = await this.sessionsRepo.updateAssignment(sessionId, {
            assignedToUserId: input.assignedToUserId,
            teamId:           input.teamId,
            assignedByUserId: actor.userId,
        });

        return mapSessionSummary(updated);
    }

    // ── Delete Session ────────────────────────────────────────────────────────

    /**
     * Soft-deletes a session and writes an audit log entry.
     * Requires session.delete permission on the session's organization.
     * Repeated deletes are idempotent (no error if already deleted).
     */
    async deleteSession(sessionId: string, actor: AuthUser): Promise<void> {
        // Note: findById only returns non-deleted sessions.
        // If already deleted we treat it as idempotent (not found → already gone → OK).
        const row = await this.sessionsRepo.findById(sessionId);
        if (!row) {
            // Already deleted or never existed — idempotent, no error needed.
            return;
        }

        await this.requirePermission(row.organization_id, actor, 'session.delete');
        await this.sessionsRepo.softDelete(sessionId, actor.userId, row.organization_id);
    }

    // ── Private Helpers ───────────────────────────────────────────────────────

    private async requireSessionExists(sessionId: string): Promise<TrainingSessionRow> {
        const row = await this.sessionsRepo.findById(sessionId);
        if (!row) throw new NotFoundError('Session not found.');
        return row;
    }

    /**
     * Returns true if the actor holds any elevated session permission
     * (session.start, session.assign, session.end, session.delete).
     * These correspond to ORG_ADMIN / TRAINER level access.
     */
    private async isElevatedActor(organizationId: string, actor: AuthUser): Promise<boolean> {
        if (actor.isSuperAdmin) return true;
        const permissions = await this.orgsRepo.findEffectivePermissions(organizationId, actor.userId);
        return ELEVATED_SESSION_PERMS.some(p => permissions.includes(p));
    }

    /**
     * Enforces session-level visibility for GET detail.
     *
     * Super admin        → always passes
     * Elevated member    → passes for any session in their org
     * Restricted member  → passes only if:
     *     - assigned_to_user_id == actorUserId  (assigned to me)
     *     - started_by_user_id  == actorUserId  (started by me)
     *     - viewer_access_scopes grants actor visibility to assigned_to_user
     */
    private async requireCanSeeSession(
        row: TrainingSessionRow,
        actor: AuthUser
    ): Promise<void> {
        if (actor.isSuperAdmin) return;

        const membership = await this.orgsRepo.findMembership(row.organization_id, actor.userId);
        if (!membership || membership.status !== 'ACTIVE' || membership.left_at !== null) {
            throw new ForbiddenError('You do not have access to this session.');
        }

        const elevated = await this.isElevatedActor(row.organization_id, actor);
        if (elevated) return;

        // Self-access: assigned to me or started by me
        if (row.assigned_to_user_id === actor.userId) return;
        if (row.started_by_user_id  === actor.userId) return;

        // Viewer scope: actor has explicit visibility grant for the session's assignee
        if (row.assigned_to_user_id) {
            const hasScope = await this.sessionsRepo.viewerHasScope(
                row.organization_id,
                actor.userId,
                row.assigned_to_user_id
            );
            if (hasScope) return;
        }

        throw new ForbiddenError('You do not have access to this session.');
    }

    private async requireActiveMember(organizationId: string, actor: AuthUser): Promise<void> {
        if (actor.isSuperAdmin) return;
        const membership = await this.orgsRepo.findMembership(organizationId, actor.userId);
        if (!membership || membership.status !== 'ACTIVE' || membership.left_at !== null) {
            throw new ForbiddenError('You are not an active member of this organization.');
        }
    }

    private async requirePermission(
        organizationId: string,
        actor: AuthUser,
        permissionCode: string
    ): Promise<void> {
        if (actor.isSuperAdmin) return;

        const membership = await this.orgsRepo.findMembership(organizationId, actor.userId);
        if (!membership || membership.status !== 'ACTIVE' || membership.left_at !== null) {
            throw new ForbiddenError('You are not an active member of this organization.');
        }

        const permissions = await this.orgsRepo.findEffectivePermissions(organizationId, actor.userId);
        if (!permissions.includes(permissionCode)) {
            throw new ForbiddenError(`You do not have the required permission: ${permissionCode}`);
        }
    }
}

