    podOrder?: number;
}

export interface SyncSessionEventInput {
    podDeviceId?: string;
    eventIndex: number;
    eventType: string;
    eventTimestamp: string; // ISO 8601
    elapsedMs?: number;
    reactionTimeMs?: number;
    isCorrect?: boolean;
    payloadJson?: Record<string, unknown>;
}

export interface SyncSessionInput {
    clientSessionId: string;
    organizationId: string;
    deviceKitId: string;
    hubDeviceId?: string;

    startedByUserId?: string;
    assignedToUserId?: string;
    teamId?: string;

    origin: 'OFFLINE_SYNC' | 'WEB' | 'ADMIN_CREATE';
    status: 'COMPLETED' | 'CANCELLED' | 'FAILED';
    endMode: 'TIME' | 'TARGET' | 'REPETITION' | 'EARLY_END';
    presetId?: string;
    trainingMode: string;
    configJson: Record<string, unknown>;

    sessionStartedAt: string; // ISO 8601
    sessionEndedAt: string;   // ISO 8601
    durationMs: number;

    score?: number;
    hitCount: number;
    missCount: number;
    accuracyPercent?: number;

    avgReactionMs?: number;
    bestReactionMs?: number;
    worstReactionMs?: number;

    notes?: string;

    activePods?: SyncSessionActivePodInput[];
    events?: SyncSessionEventInput[];
}

export interface ListSessionsFilters {
    organizationId?: string;
    assignedToUserId?: string;
    teamId?: string;
    limit?: number;   // default 50, max 200
    offset?: number;  // default 0
}

export interface AssignSessionInput {
    assignedToUserId?: string | null;
    teamId?: string | null;
}

// ─── Response Shapes ──────────────────────────────────────────────────────────

export interface ActivePodItem {
    id: string;
    podDeviceId: string;
    podOrder: number | null;
}

export interface SessionEventItem {
    id: string;
    podDeviceId: string | null;
    eventIndex: number;
    eventType: string;
    eventTimestamp: Date;
    elapsedMs: number | null;
    reactionTimeMs: number | null;
    isCorrect: boolean | null;
    payloadJson: Record<string, unknown> | null;
}

export interface SessionSummary {
    id: string;
    organizationId: string;
    deviceKitId: string;
    hubDeviceId: string | null;

    startedByUserId: string | null;
    assignedToUserId: string | null;
    assignedByUserId: string | null;
    teamId: string | null;

    origin: string;
    syncStatus: string;
    clientSessionId: string | null;

    status: string;
    endMode: string;
    presetId: string | null;
    trainingMode: string;

    sessionStartedAt: Date;
    sessionEndedAt: Date;
    durationMs: number;

    score: number | null;
    hitCount: number;
    missCount: number;
    accuracyPercent: number | null;

    avgReactionMs: number | null;
    bestReactionMs: number | null;
    worstReactionMs: number | null;

    activePodCount: number;
    totalEventsCount: number;
    notes: string | null;

    createdAt: Date;
    updatedAt: Date;
}

export interface SessionDetail extends SessionSummary {
    configJson: Record<string, unknown>;
    activePods: ActivePodItem[];
    events: SessionEventItem[];
}

export interface SessionListResult {
    sessions: SessionSummary[];
    total:    number;
    limit:    number;
    offset:   number;
}

import { Request, Response, NextFunction } from 'express';
import { UnauthorizedError } from '../../shared/errors/http-errors.js';
import { sendSuccess } from '../../shared/utils/response.js';
import { TeamsService } from './teams.service.js';
import { listTeamsQuerySchema } from './teams.validation.js';
import { CreateTeamInput, AddTeamMemberInput } from './teams.types.js';

export class TeamsController {
    constructor(private readonly teamsService: TeamsService) {}

    // POST /teams
    create = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            const team = await this.teamsService.createTeam(req.body as CreateTeamInput, req.user);
            sendSuccess(res, { team }, 201);
        } catch (err) { next(err); }
    };

    // GET /teams
    list = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            const parsed = listTeamsQuerySchema.safeParse(req.query);
            const filters = parsed.success ? parsed.data : {};
            const teams = await this.teamsService.listTeams(filters, req.user);
            sendSuccess(res, { teams });
        } catch (err) { next(err); }
    };

    // GET /teams/:teamId
    getDetail = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            const team = await this.teamsService.getTeamDetail(
                req.params['teamId'] as string,
                req.user
            );
            sendSuccess(res, { team });
        } catch (err) { next(err); }
    };

    // POST /teams/:teamId/members
    addMember = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            const members = await this.teamsService.addTeamMember(
                req.params['teamId'] as string,
                req.body as AddTeamMemberInput,
                req.user
            );
            sendSuccess(res, { members }, 201);
        } catch (err) { next(err); }
    };

    // GET /teams/:teamId/members
    listMembers = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            const members = await this.teamsService.listTeamMembers(
                req.params['teamId'] as string,
                req.user
            );
            sendSuccess(res, { members });
        } catch (err) { next(err); }
    };

    // DELETE /teams/:teamId/members/:userId
    removeMember = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        try {
            if (!req.user) return next(new UnauthorizedError());
            await this.teamsService.removeTeamMember(
                req.params['teamId'] as string,
                req.params['userId'] as string,
                req.user
            );
            sendSuccess(res, null, 200);
        } catch (err) { next(err); }
    };
}

